async def pagina_inicial(request):
    gerar_catalogo_html()
    return web.FileResponse(CATALOGO_HTML)


async def obter_canal_por_id(canal_id: int):
    if not canal_id:
        return None

    canal = bot.get_channel(canal_id)
    if canal is not None:
        return canal

    try:
        return await bot.fetch_channel(canal_id)
    except Exception:
        return None


async def apagar_mensagens_discord_do_registro(
    registro: Dict[str, Any],
) -> None:
    """Apaga o post ativo e/ou o post arquivado relacionado ao registro."""
    alvos = [
        (PROCURADOS_CHANNEL_ID, registro.get("mensagem_id")),
        (
            HISTORICO_PROCURADOS_ID,
            registro.get("mensagem_arquivada_id"),
        ),
    ]

    for canal_id, mensagem_id in alvos:
        if not canal_id or not mensagem_id:
            continue

        canal = await obter_canal_por_id(int(canal_id))
        if canal is None or not hasattr(canal, "fetch_message"):
            continue

        try:
            mensagem = await canal.fetch_message(int(mensagem_id))
            await mensagem.delete()
        except discord.NotFound:
            pass
        except Exception as erro:
            await enviar_log(
                f"⚠️ Não foi possível apagar a mensagem `{mensagem_id}` "
                f"do registro `{registro.get('id')}`: {erro}"
            )


def apagar_arquivos_locais_do_registro(
    registro: Dict[str, Any],
) -> None:
    """Remove as fotos locais pertencentes ao registro apagado."""
    for chave in ("foto_individuo", "foto_rg"):
        caminho_relativo = str(registro.get(chave, "") or "").strip()

        if (
            not caminho_relativo
            or not caminho_relativo.startswith("uploads/")
        ):
            continue

        caminho = PUBLIC_DIR / caminho_relativo
        try:
            caminho_resolvido = caminho.resolve()
            uploads_resolvido = UPLOADS_DIR.resolve()

            if (
                uploads_resolvido in caminho_resolvido.parents
                and caminho_resolvido.exists()
            ):
                caminho_resolvido.unlink()
        except Exception:
            pass


async def api_apagar_procurado(
    request: web.Request,
) -> web.Response:
    ip = request.remote or "desconhecido"

    if not catalogo_limite_tentativas(ip):
        return web.json_response(
            {
                "ok": False,
                "erro": "Muitas tentativas. Aguarde 10 minutos.",
            },
            status=429,
        )

    try:
        dados = await request.json()
    except Exception:
        return web.json_response(
            {"ok": False, "erro": "Requisição inválida."},
            status=400,
        )

    senha = str(dados.get("senha", "") or "")
    registro_id = str(dados.get("id", "") or "").strip()

    if not senha_catalogo_valida(senha):
        registrar_falha_senha_catalogo(ip)
        return web.json_response(
            {"ok": False, "erro": "Senha incorreta."},
            status=401,
        )

    if not registro_id:
        return web.json_response(
            {"ok": False, "erro": "Registro não informado."},
            status=400,
        )

    lista = carregar_procurados()
    encontrado = None
    nova_lista: List[Dict[str, Any]] = []

    for registro in lista:
        identificador = str(
            registro.get("id")
            or registro.get("caso")
            or registro.get("rg")
            or ""
        )

        if encontrado is None and identificador == registro_id:
            encontrado = registro
            continue

        nova_lista.append(registro)

    if encontrado is None:
        return web.json_response(
            {
                "ok": False,
                "erro": "O procurado já foi apagado ou não existe.",
            },
            status=404,
        )

    # Remove fisicamente do JSON. Assim não aparece em nenhuma aba.
    salvar_procurados(nova_lista)
    gerar_catalogo_html()

    # Limpa, quando possível, os posts e as fotos relacionados.
    await apagar_mensagens_discord_do_registro(encontrado)
    apagar_arquivos_locais_do_registro(encontrado)

    catalogo_tentativas_senha.pop(ip, None)

    await enviar_log(
        f"🗑️ **Procurado apagado permanentemente pelo catálogo**\n"
        f"Nome: {encontrado.get('nome')}\n"
        f"RG: {encontrado.get('rg')}\n"
        f"Registro: {registro_id}"
    )

    return web.json_response(
        {
            "ok": True,
            "mensagem": "Registro apagado permanentemente.",
        }
    )




def normalizar_url_publica_base(valor: str) -> str:
    """Limpa o domínio público usado em botões de download.

    Evita o erro do Discord `Not a well formed URL` quando a variável vem com
    `<...>`, markdown, espaços ou sem `https://`.
    """
    url_base = str(valor or "").strip()
    url_base = url_base.strip("`'\" ")
    if url_base.startswith("<") and url_base.endswith(">"):
        url_base = url_base[1:-1].strip()
    url_base = url_base.rstrip("/")
    if not url_base:
        return ""
    if not re.match(r"^https?://", url_base, flags=re.I):
        url_base = "https://" + url_base
    try:
        parsed = urlparse(url_base)
        if parsed.scheme not in {"http", "https"} or not parsed.netloc or any(ch.isspace() for ch in url_base):
            return ""
    except Exception:
        return ""
    return url_base


def url_discord_valida(url: str) -> bool:
    try:
        url = str(url or "").strip()
        if not url or len(url) > 500:
            return False
        parsed = urlparse(url)
        return parsed.scheme in {"http", "https"} and bool(parsed.netloc) and not any(ch.isspace() for ch in url)
    except Exception:
        return False


def dossie_download_url(caminho: Any, nome_download: Optional[str] = None) -> str:
    """Monta link público para baixar dossiês sem depender do upload do Discord."""
    try:
        caminho_path = Path(str(caminho)).resolve()
        base_dir = DOSSIES_DIR.resolve()
        if base_dir not in caminho_path.parents:
            return ""
        rel = caminho_path.relative_to(base_dir)
        partes = [quote(parte) for parte in rel.parts]
        url_base = normalizar_url_publica_base(DOSSIE_PUBLIC_URL or CATALOG_PUBLIC_URL or "")
        if not url_base:
            return ""
        url = f"{url_base}/dossies/{'/'.join(partes)}?download=1"
        if nome_download:
            url += f"&nome={quote(str(nome_download))}"
        return url if url_discord_valida(url) else ""
    except Exception:
        return ""


async def baixar_dossie_http(request: web.Request) -> web.StreamResponse:
    """Endpoint protegido contra path traversal para baixar PDF/DOCX gerados."""
    rel = str(request.match_info.get("caminho", "") or "").strip().replace("\\", "/")
    if not rel or ".." in rel.split("/"):
        return web.Response(status=404, text="Arquivo não encontrado.")

    try:
        caminho = (DOSSIES_DIR / rel).resolve()
        base_dir = DOSSIES_DIR.resolve()
        if base_dir not in caminho.parents or not caminho.exists() or not caminho.is_file():
            return web.Response(status=404, text="Arquivo não encontrado.")

        nome = request.query.get("nome") or caminho.name
        nome_seguro = re.sub(r"[^A-Za-z0-9_.\-() ]+", "_", str(nome))[:180] or caminho.name
        headers = {
            "Content-Disposition": f'attachment; filename="{nome_seguro}"',
            "X-Content-Type-Options": "nosniff",
        }
        return web.FileResponse(path=str(caminho), headers=headers)
    except Exception as erro:
        await enviar_log(f"❌ Erro ao servir download de dossiê: {erro}")
        return web.Response(status=500, text="Falha ao preparar download.")


def backup_download_url(caminho: Any, nome_download: Optional[str] = None) -> str:
    """Monta link público para baixar backups completos sem anexar arquivos gigantes no Discord."""
    try:
        caminho_path = Path(str(caminho)).resolve()
        base_dir = PUBLIC_BACKUPS_DIR.resolve()
        if base_dir not in caminho_path.parents and caminho_path != base_dir:
            return ""
        rel = caminho_path.relative_to(base_dir)
        partes = [quote(parte) for parte in rel.parts]
        url_base = (SERVER_BACKUP_PUBLIC_URL or DOSSIE_PUBLIC_URL or CATALOG_PUBLIC_URL or "").strip().rstrip("/")
        if not url_base:
            return ""
        if not re.match(r"^https?://", url_base, flags=re.I):
            url_base = "https://" + url_base
        url = f"{url_base}/backups/{'/'.join(partes)}?download=1"
        if nome_download:
            url += f"&nome={quote(str(nome_download))}"
        return url
    except Exception:
        return ""


async def baixar_backup_http(request: web.Request) -> web.StreamResponse:
    """Endpoint protegido para baixar ZIPs de backup completos."""
    rel = str(request.match_info.get("caminho", "") or "").strip().replace("\\", "/")
    if not rel or ".." in rel.split("/"):
        return web.Response(status=404, text="Backup não encontrado.")

    try:
        caminho = (PUBLIC_BACKUPS_DIR / rel).resolve()
        base_dir = PUBLIC_BACKUPS_DIR.resolve()
        if base_dir not in caminho.parents or not caminho.exists() or not caminho.is_file():
            return web.Response(status=404, text="Backup não encontrado.")

        nome = request.query.get("nome") or caminho.name
        nome_seguro = re.sub(r"[^A-Za-z0-9_.\-() ]+", "_", str(nome))[:180] or caminho.name
        headers = {
            "Content-Disposition": f'attachment; filename="{nome_seguro}"',
            "X-Content-Type-Options": "nosniff",
        }
        return web.FileResponse(path=str(caminho), headers=headers)
    except Exception as erro:
        await enviar_log(f"❌ Erro ao servir download de backup: {erro}")
        return web.Response(status=500, text="Falha ao preparar backup.")

async def start_web_server():
    gerar_catalogo_html()
    app = web.Application()
    app.router.add_get("/", pagina_inicial)
    app.router.add_get("/index.html", pagina_inicial)
    app.router.add_get("/dossies/{caminho:.+}", baixar_dossie_http)
    app.router.add_get("/backups/{caminho:.+}", baixar_backup_http)
    app.router.add_post(
        "/api/catalogo/apagar",
        api_apagar_procurado,
    )
    app.router.add_static(
        "/uploads/",
        path=str(UPLOADS_DIR),
        show_index=False,
    )
    runner = web.AppRunner(app)
    await runner.setup()
    site = web.TCPSite(runner, "0.0.0.0", PORT)
    await site.start()
    print(f"Catalogo rodando na porta {PORT}")

