def obter_assinaturas_dossie(dados: Dict[str, Any]) -> List[Dict[str, Any]]:
    """Retorna somente as duas assinaturas institucionais exigidas no dossiê."""
    registros = carregar_assinaturas_dossie()
    diretor_geral = registros.get("diretor_geral") or registros.get("delegado_geral") or {}
    diretor_dicor = registros.get("diretor_dicor") or registros.get("delegado_dicor") or {}
    return [
        {
            "titulo": "DIRETOR GERAL",
            "nome": diretor_geral.get("nome") or "Diretor Geral",
            "texto": diretor_geral.get("texto") or ASSINATURA_DELEGADO_GERAL_TEXTO,
            "imagem": caminho_assinatura_registrada(diretor_geral) or caminho_arquivo_configurado(
                ASSINATURA_DELEGADO_GERAL_IMAGEM,
                ["assinatura_diretor_geral.png", "assinatura_delegado_geral.png", "assinatura_delegado_geral.jpg"],
            ),
        },
        {
            "titulo": "DIRETOR DICOR",
            "nome": diretor_dicor.get("nome") or "Diretor DICOR",
            "texto": diretor_dicor.get("texto") or ASSINATURA_DELEGADO_DICOR_TEXTO,
            "imagem": caminho_assinatura_registrada(diretor_dicor) or caminho_arquivo_configurado(
                ASSINATURA_DELEGADO_DICOR_IMAGEM,
                ["assinatura_diretor_dicor.png", "assinatura_delegado_dicor.png", "assinatura_delegado_dicor.jpg"],
            ),
        },
    ]


