def _wrap_pdf(c, texto: str, fonte: str, tamanho: float, largura_max: float) -> List[str]:
    linhas = []
    for bloco in str(texto or "").splitlines() or [""]:
        linha = ""
        for palavra in bloco.split():
            teste = (linha + " " + palavra).strip()
            try:
                ok = c.stringWidth(teste, fonte, tamanho) <= largura_max
            except Exception:
                ok = len(teste) < 85
            if ok or not linha:
                linha = teste
            else:
                linhas.append(linha)
                linha = palavra
        if linha:
            linhas.append(linha)
        elif not bloco.strip():
            linhas.append("")
    return linhas


def _draw_logo_comparecimento(c, caminho: Optional[Path], x: float, y: float, w: float, h: float) -> None:
    try:
        if caminho and Path(caminho).exists():
            c.drawImage(str(caminho), x, y, width=w, height=h, preserveAspectRatio=True, mask="auto")
    except Exception:
        pass






def gerar_pdf_comparecimento(registro: Dict[str, Any], caminho_pdf: Path) -> None:
    """Gera a solicitação de comparecimento no modelo aprovado, com texto longo paginado e sem sobreposição."""
    if canvas is None or A4 is None:
        raise RuntimeError("Dependência ausente: instale reportlab.")
    caminho_pdf.parent.mkdir(parents=True, exist_ok=True)

    c = canvas.Canvas(str(caminho_pdf), pagesize=A4)
    largura, altura = A4
    template = caminho_modelo_visual_canva()

    branco = colors.HexColor("#111111")
    dourado = colors.HexColor("#8A6500")
    azul_claro = colors.HexColor("#53798A")
    preto = colors.HexColor("#FFFFFF")

    margem_x = 1.22 * cm
    largura_util = largura - 2 * margem_x
    painel_topo = altura - 5.65 * cm
    limite_baixo = 2.15 * cm
    painel_altura = painel_topo - limite_baixo

    local_comparecimento = str(registro.get("local") or "Sede da Polícia Federal - DICOR")
    data_comparecimento = str(registro.get("data_hora") or "a definir")

    def _safe(txt: Any) -> str:
        return str(txt if txt is not None else "Não informado").replace(chr(13), "").strip() or "Não informado"

    def _set_alpha(fill=1, stroke=1):
        try:
            c.setFillAlpha(fill)
            c.setStrokeAlpha(stroke)
        except Exception:
            pass

    def _draw_template() -> None:
        # Fundo claro com marca d'água central. A moldura e os brasões continuam
        # sendo desenhados pelo próprio documento, sem o fundo preto do modelo antigo.
        c.setFillColor(colors.HexColor("#F7F7F4"))
        c.rect(0, 0, largura, altura, fill=1, stroke=0)
        try:
            wm = caminho_marca_dagua_dicor()
            if wm and Path(wm).exists():
                c.saveState()
                try:
                    c.setFillAlpha(0.08)
                    c.setStrokeAlpha(0.08)
                except Exception:
                    pass
                w = 12.5 * cm
                h = 14.7 * cm
                c.drawImage(str(wm), (largura-w)/2, (altura-h)/2-0.5*cm, width=w, height=h, preserveAspectRatio=True, mask="auto")
                c.restoreState()
        except Exception:
            pass

    def _linhas(texto: Any, fonte="Courier", tam=8.95, largura_max=None) -> List[str]:
        largura_max = largura_max or (largura_util - 0.70 * cm)
        saida: List[str] = []
        for bloco in _safe(texto).splitlines():
            bloco = bloco.strip()
            if not bloco:
                saida.append("")
                continue
            try:
                saida.extend(_wrap_pdf(c, bloco, fonte, tam, largura_max))
            except Exception:
                import textwrap as _tw
                chars = max(40, int(largura_max / (tam * 0.55)))
                saida.extend(_tw.wrap(bloco, chars, break_long_words=False) or [""])
        return saida

    def _pagina(titulo: str) -> float:
        _draw_template()
        # Brasões oficiais: PF à esquerda e o novo brasão DICOR à direita.
        try:
            pf = caminho_brasao_pf()
            dicor = caminho_brasao_dicor()
            _draw_logo_comparecimento(c, pf, margem_x + 0.25 * cm, altura - 4.85 * cm, 3.15 * cm, 3.15 * cm)
            _draw_logo_comparecimento(c, dicor, largura - margem_x - 3.40 * cm, altura - 4.85 * cm, 3.15 * cm, 3.15 * cm)
            c.setFillColor(dourado)
            c.setFont("Courier-Bold", 10.2)
            c.drawCentredString(largura / 2, altura - 2.45 * cm, "POLÍCIA FEDERAL • DICOR")
            c.setFont("Courier", 8.0)
            c.drawCentredString(largura / 2, altura - 2.82 * cm, "CAPITAL MORADA DO VALLEY")
        except Exception:
            pass
        _set_alpha(0.86, 1)
        c.setFillColor(preto)
        c.roundRect(margem_x, limite_baixo, largura_util, painel_altura, 7, fill=1, stroke=0)
        _set_alpha(1, 1)
        c.setStrokeColor(azul_claro)
        c.setLineWidth(0.85)
        c.roundRect(margem_x, limite_baixo, largura_util, painel_altura, 7, fill=0, stroke=1)
        faixa_h = 0.72 * cm
        faixa_y = painel_topo - faixa_h
        c.setFillColor(colors.HexColor("#111111"))
        c.rect(margem_x + 0.08 * cm, faixa_y, largura_util - 0.16 * cm, faixa_h, stroke=0, fill=1)
        c.setStrokeColor(dourado)
        c.setLineWidth(0.75)
        c.line(margem_x + 0.18 * cm, faixa_y + 0.12 * cm, largura - margem_x - 0.18 * cm, faixa_y + 0.12 * cm)
        c.setFillColor(dourado)
        c.setFont("Courier-Bold", 11.7)
        c.drawString(margem_x + 0.28 * cm, faixa_y + 0.28 * cm, titulo.upper()[:78])
        return faixa_y - 0.36 * cm

    def _nova_pagina(titulo: str) -> float:
        c.showPage()
        return _pagina(titulo)

    def _precisa(y: float, espaco: float, titulo: str) -> float:
        if y - espaco < limite_baixo + 0.55 * cm:
            return _nova_pagina(titulo + " - CONTINUAÇÃO")
        return y

    def _campo(label: str, valor: Any, y: float, titulo: str, label_w: float = 4.4 * cm) -> float:
        linhas = _linhas(valor, "Courier", 9.15, largura_util - label_w - 0.70 * cm)
        if not linhas:
            linhas = ["Não informado"]
        precisa = max(0.46 * cm, len(linhas) * 0.35 * cm + 0.08 * cm)
        y = _precisa(y, precisa, titulo)
        c.setFont("Courier-Bold", 9.2)
        c.setFillColor(dourado)
        c.drawString(margem_x + 0.32 * cm, y, f"{label}:")
        c.setFont("Courier", 9.15)
        c.setFillColor(branco)
        vx = margem_x + 0.32 * cm + label_w
        for idx, linha in enumerate(linhas[:4]):
            c.drawString(vx, y - idx * 0.34 * cm, linha[:145])
        return y - precisa

    def _subtitulo(t: str, y: float, titulo: str) -> float:
        y = _precisa(y, 0.72 * cm, titulo)
        c.setStrokeColor(dourado)
        c.setFillColor(colors.HexColor("#EEF1F1"))
        c.roundRect(margem_x + 0.22 * cm, y - 0.46 * cm, largura_util - 0.44 * cm, 0.55 * cm, 4, fill=1, stroke=1)
        c.setFillColor(dourado)
        c.setFont("Courier-Bold", 9.9)
        c.drawString(margem_x + 0.42 * cm, y - 0.28 * cm, t.upper()[:78])
        return y - 0.86 * cm

    def _texto(texto: Any, y: float, titulo: str, tam: float = 8.85, leading: float = 0.36 * cm) -> float:
        c.setFont("Courier", tam)
        c.setFillColor(branco)
        for linha in _linhas(texto, "Courier", tam, largura_util - 0.70 * cm):
            y = _precisa(y, leading + 0.06 * cm, titulo)
            if linha == "":
                y -= leading * 0.70
                continue
            c.drawString(margem_x + 0.35 * cm, y, linha[:170])
            y -= leading
        return y

    texto_oficial = f"""O Departamento de Inteligência e Combate ao Crime Organizado - DICOR, no uso de suas atribuições legais e em conformidade com os procedimentos administrativos e investigativos vigentes, SOLICITA o comparecimento de Vossa Senhoria para prestar esclarecimentos e colaborar com a investigação em andamento, vinculada ao processo em epígrafe.

O comparecimento deverá ocorrer no local informado para comparecimento ({local_comparecimento}), na data e horário previamente estabelecidos para comparecimento ({data_comparecimento}), ocasião em que serão realizados os procedimentos pertinentes à instrução da investigação.

A presente solicitação tem por finalidade possibilitar a coleta de informações relevantes para o regular prosseguimento dos trabalhos investigativos, assegurando a observância dos princípios da legalidade, da ampla apuração dos fatos e do devido procedimento administrativo.

Ressalta-se que o não comparecimento injustificado poderá ensejar a adoção das medidas administrativas e legais cabíveis, sem prejuízo de outras providências que se fizerem necessárias para o regular andamento da investigação.

Solicita-se que Vossa Senhoria apresente documento oficial de identificação no momento do comparecimento e observe rigorosamente a data, o horário e o local indicados neste documento.

Sem mais para o momento, renovamos nossos votos de elevada consideração e colocamo-nos à disposição para eventuais esclarecimentos que se façam necessários."""

    titulo_base = "SOLICITAÇÃO DE COMPARECIMENTO"
    y = _pagina(titulo_base)
    y = _subtitulo("IDENTIFICAÇÃO", y, titulo_base)
    y = _campo("Solicitação", registro.get("numero", "00000-0000"), y, titulo_base)
    y = _campo("Data de Expedição", registro.get("data_expedicao", agora_br()), y, titulo_base)
    y = _campo("Nº do Processo", registro.get("processo", "Não informado"), y, titulo_base)
    y = _subtitulo("IDENTIFICAÇÃO DO CONVOCADO", y, titulo_base)
    y = _campo("A(o) Sr.(a)", registro.get("nome", "Não informado"), y, titulo_base)
    y = _campo("RG", registro.get("rg", "Não informado"), y, titulo_base)
    y = _subtitulo("LOCAL E DATA PARA COMPARECIMENTO", y, titulo_base)
    y = _campo("Local para comparecimento", local_comparecimento, y, titulo_base, label_w=6.7 * cm)
    y = _campo("Data para comparecimento", data_comparecimento, y, titulo_base, label_w=6.7 * cm)
    y = _campo("Motivo", registro.get("motivo", "Não informado"), y, titulo_base)
    y = _subtitulo("TEXTO OFICIAL", y, titulo_base)
    y = _texto(texto_oficial, y, titulo_base, tam=8.75, leading=0.34 * cm)

    # Assinatura exata da autoridade que clicou em Autorizar.
    assinatura = obter_assinatura_comparecimento(registro.get("autorizado_por_id"))
    y = _precisa(y, 3.15 * cm, titulo_base)
    imagem_ass = assinatura.get("arquivo") if assinatura else None
    if imagem_ass and Path(str(imagem_ass)).exists():
        try:
            c.drawImage(str(imagem_ass), largura/2-2.6*cm, y-1.45*cm, width=5.2*cm, height=1.35*cm, preserveAspectRatio=True, mask="auto")
        except Exception:
            pass
    c.setStrokeColor(colors.HexColor("#777777"))
    c.line(4.4 * cm, y - 1.55 * cm, largura - 4.4 * cm, y - 1.55 * cm)
    nome_ass = (assinatura or {}).get("nome") or registro.get("autorizado_por_nome") or "Autoridade responsável"
    cargo_ass = (assinatura or {}).get("cargo") or registro.get("autorizado_por_cargo") or "Inspetor DICOR ou superior"
    c.setFillColor(colors.HexColor("#111111"))
    c.setFont("Courier-Bold", 9.1)
    c.drawCentredString(largura / 2, y - 1.90 * cm, str(nome_ass)[:65])
    c.setFont("Courier", 8.1)
    c.drawCentredString(largura / 2, y - 2.22 * cm, str(cargo_ass)[:65])
    c.drawCentredString(largura / 2, y - 2.52 * cm, f"Autorizado em: {registro.get('autorizado_em', agora_br())}")
    c.save()

def gerar_docx_comparecimento(registro: Dict[str, Any], caminho_docx: Path) -> None:
    if Document is None:
        raise RuntimeError("Dependência ausente: instale python-docx.")
    caminho_docx.parent.mkdir(parents=True, exist_ok=True)
    doc = Document()
    try:
        sec = doc.sections[0]
        sec.top_margin = Inches(0.55)
        sec.bottom_margin = Inches(0.55)
        sec.left_margin = Inches(0.60)
        sec.right_margin = Inches(0.60)
    except Exception:
        pass
    p = doc.add_paragraph()
    p.alignment = WD_ALIGN_PARAGRAPH.CENTER
    run = p.add_run("POLÍCIA FEDERAL\nDO ESTADO DA CAPITAL\nMORADA DO VALLEY")
    run.bold = True
    try:
        run.font.size = Pt(15)
    except Exception:
        pass
    p2 = doc.add_paragraph()
    p2.alignment = WD_ALIGN_PARAGRAPH.CENTER
    r2 = p2.add_run(f"SOLICITAÇÃO DE COMPARECIMENTO: {registro.get('numero', '00000-0000')}")
    r2.bold = True
    try:
        r2.font.size = Pt(13)
    except Exception:
        pass
    tabela = doc.add_table(rows=0, cols=2)
    tabela.style = "Table Grid"
    campos = [
        ("Data de Expedição", registro.get("data_expedicao", agora_br())),
        ("Nº do Processo", registro.get("processo", "Não informado")),
        ("Convocado", registro.get("nome", "Não informado")),
        ("RG", registro.get("rg", "Não informado")),
        ("Data para comparecimento", registro.get("data_hora", "Não informado")),
        ("Local para comparecimento", registro.get("local", "Não informado")),
        ("Motivo", registro.get("motivo", "Não informado")),
    ]
    for k, v in campos:
        row = tabela.add_row().cells
        row[0].text = str(k)
        row[1].text = str(v)
    local_comparecimento = str(registro.get("local") or "Sede da Polícia Federal - DICOR")
    data_comparecimento = str(registro.get("data_hora") or "a definir")
    texto = f"""O Departamento de Inteligência e Combate ao Crime Organizado - DICOR, no uso de suas atribuições legais e em conformidade com os procedimentos administrativos e investigativos vigentes, SOLICITA o comparecimento de Vossa Senhoria para prestar esclarecimentos e colaborar com a investigação em andamento, vinculada ao processo em epígrafe.

O comparecimento deverá ocorrer no local informado para comparecimento ({local_comparecimento}), na data e horário previamente estabelecidos para comparecimento ({data_comparecimento}), ocasião em que serão realizados os procedimentos pertinentes à instrução da investigação.

A presente solicitação tem por finalidade possibilitar a coleta de informações relevantes para o regular prosseguimento dos trabalhos investigativos, assegurando a observância dos princípios da legalidade, da ampla apuração dos fatos e do devido procedimento administrativo.

Ressalta-se que o não comparecimento injustificado poderá ensejar a adoção das medidas administrativas e legais cabíveis, sem prejuízo de outras providências que se fizerem necessárias para o regular andamento da investigação.

Solicita-se que Vossa Senhoria apresente documento oficial de identificação no momento do comparecimento e observe rigorosamente a data, o horário e o local indicados neste documento.

Sem mais para o momento, renovamos nossos votos de elevada consideração e colocamo-nos à disposição para eventuais esclarecimentos que se façam necessários."""
    p = doc.add_paragraph(texto)
    p.alignment = WD_ALIGN_PARAGRAPH.JUSTIFY
    doc.add_paragraph("\n\n________________________________________")
    p = doc.add_paragraph("POLÍCIA FEDERAL - DICOR")
    p.alignment = WD_ALIGN_PARAGRAPH.CENTER
    p = doc.add_paragraph(f"Emitido por: {registro.get('solicitado_por_nome', 'Sistema DICOR')}")
    p.alignment = WD_ALIGN_PARAGRAPH.CENTER
    doc.save(str(caminho_docx))

