DICOR_WATERMARK_FILE = DOSSIE_ASSETS_DIR / "marca_dagua_dicor.png"


def caminho_marca_dagua_dicor() -> Optional[Path]:
    try:
        DOSSIE_ASSETS_DIR.mkdir(parents=True, exist_ok=True)
        if not DICOR_WATERMARK_FILE.exists():
            DICOR_WATERMARK_FILE.write_bytes(base64.b64decode(DICOR_WATERMARK_B64))
        return DICOR_WATERMARK_FILE if DICOR_WATERMARK_FILE.exists() else None
    except Exception:
        return None


def _json_dict(caminho: Path) -> Dict[str, Any]:
    d = carregar_json(caminho, {})
    return d if isinstance(d, dict) else {}


def _salvar_dict(caminho: Path, d: Dict[str, Any]) -> None:
    caminho.parent.mkdir(parents=True, exist_ok=True)
    salvar_json(caminho, d)



async def apagar_mensagem_original_procurado(registro: Dict[str, Any], guild: Optional[discord.Guild]) -> bool:
    if guild is None:
        return False
    canal_id = int(registro.get("canal_id") or PROCURADOS_CHANNEL_ID or 0)
    canal = guild.get_channel(canal_id) if canal_id else None
    if canal is None and canal_id:
        try:
            canal = await bot.fetch_channel(canal_id)
        except Exception:
            canal = None
    if canal is None:
        return False
    ids = [registro.get("mensagem_id"), registro.get("mensagem_original_id")]
    for mid in ids:
        if not mid:
            continue
        try:
            msg = await canal.fetch_message(int(mid))
            await msg.delete(reason="Procurado retirado e arquivado por Inspetor+")
            return True
        except Exception:
            pass
    # Segurança para registros antigos sem ID: procura RG e nome no histórico.
    rg = limpar_rg(registro.get("rg", ""))
    nome = normalizar_busca(registro.get("nome", ""))
    try:
        async for msg in canal.history(limit=None, oldest_first=False):
            texto_msg = coletar_texto_embed(msg)
            norm = normalizar_busca(texto_msg)
            if (rg and rg in limpar_rg(texto_msg)) or (nome and nome in norm):
                await msg.delete(reason="Procurado antigo localizado por RG/nome e arquivado")
                return True
    except Exception:
        pass
    return False


