def _drafts_relatorios() -> Dict[str, Any]:
    return _json_dict(RELATORIOS_DRAFTS_JSON)


def _salvar_draft(canal_id: int, dados: Dict[str, Any]) -> None:
    d = _drafts_relatorios(); d[str(canal_id)] = dados; _salvar_dict(RELATORIOS_DRAFTS_JSON, d)


def _obter_draft(canal_id: int) -> Optional[Dict[str, Any]]:
    return _drafts_relatorios().get(str(canal_id))


def _remover_draft(canal_id: int) -> None:
    d = _drafts_relatorios(); d.pop(str(canal_id), None); _salvar_dict(RELATORIOS_DRAFTS_JSON, d)


async def _criar_canal_fotos_relatorio(interaction: discord.Interaction, tipo: str, texto: str, numero: str) -> None:
    guild = interaction.guild
    if guild is None:
        return await interaction.followup.send("❌ Servidor não encontrado.", ephemeral=True)
    overwrites = {
        guild.default_role: discord.PermissionOverwrite(view_channel=False),
        interaction.user: discord.PermissionOverwrite(view_channel=True, send_messages=True, attach_files=True, embed_links=True, read_message_history=True),
        guild.me: discord.PermissionOverwrite(view_channel=True, send_messages=True, manage_channels=True, manage_messages=True, attach_files=True, read_message_history=True),
    }
    for role in guild.roles:
        if role.id in set(CARGOS_EQUIPE_IDS + CARGOS_ADMIN_IDS):
            overwrites[role] = discord.PermissionOverwrite(view_channel=True, send_messages=True, attach_files=True, read_message_history=True)
    categoria = guild.get_channel(CATEGORIA_RELATORIOS_TEMPORARIOS)
    slug = re.sub(r"[^a-z0-9-]+", "-", normalizar_busca(interaction.user.display_name)).strip("-")[:25]
    canal = await guild.create_text_channel(
        name=f"fotos-{tipo}-{numero}-{slug}"[:95], category=categoria, overwrites=overwrites,
        reason="Canal provisório para anexar fotos do relatório DICOR",
    )
    _salvar_draft(canal.id, {
        "tipo": tipo, "numero": numero, "texto": texto,
        "autor_id": interaction.user.id, "autor_nome": str(interaction.user),
        "criado_em": agora_br(), "canal_destino_id": CANAIS_RELATORIOS.get(tipo),
    })
    embed = discord.Embed(
        title="📸 ANEXE AS FOTOS DO RELATÓRIO",
        description=(
            "O formulário já foi salvo. Agora envie **todas as fotos, vídeos e provas** diretamente neste canal, na ordem correta.\n\n"
            "Quando terminar, clique em **Finalizar relatório**. O bot primeiro salvará os arquivos, depois enviará o formulário e os anexos juntos ao canal oficial."
        ), color=discord.Color.blurple(),
    )
    embed.add_field(name="Prévia", value=cortar_discord(texto.replace("*", ""), 1000), inline=False)
    await canal.send(content=interaction.user.mention, embed=embed, view=FinalizarRelatorioFotosView())
    await interaction.followup.send(f"✅ Formulário salvo. Envie as fotos em {canal.mention} e finalize por lá.", ephemeral=True)


async def _baixar_bytes_url(session: ClientSession, url: str) -> Optional[bytes]:
    if not url:
        return None
    try:
        async with session.get(url, timeout=ClientTimeout(total=45)) as resp:
            if resp.status == 200:
                data = await resp.read()
                if data:
                    return data
    except Exception:
        return None
    return None


async def _salvar_anexos_canal(canal: discord.TextChannel, pasta: Path) -> List[Dict[str, Any]]:
    pasta.mkdir(parents=True, exist_ok=True)
    itens: List[Dict[str, Any]] = []
    async with ClientSession() as session:
        async for msg in canal.history(limit=None, oldest_first=True):
            for indice, anexo in enumerate(msg.attachments):
                nome = re.sub(r"[^A-Za-z0-9._-]+", "_", anexo.filename or f"anexo_{msg.id}_{indice}")
                destino = pasta / f"{len(itens)+1:03d}_{nome}"
                dados = None
                try:
                    dados = await anexo.read(use_cached=True)
                except Exception:
                    dados = await _baixar_bytes_url(session, anexo.url)
                    if not dados:
                        dados = await _baixar_bytes_url(session, getattr(anexo, "proxy_url", ""))
                if not dados:
                    continue
                if len(dados) > RELATORIOS_MAX_ANEXO_MB * 1024 * 1024:
                    continue
                destino.write_bytes(dados)
                itens.append({"arquivo": str(destino), "nome": anexo.filename, "ordem": len(itens)+1, "origem_mensagem_id": msg.id})
    return itens


async def _enviar_relatorio_com_arquivos(canal_destino, texto: str, arquivos: List[Dict[str, Any]], view: Optional[View] = None) -> List[discord.Message]:
    mensagens=[]
    for inicio in range(0, max(1, len(arquivos)), 10):
        lote=arquivos[inicio:inicio+10]
        files=[]
        for item in lote:
            p=Path(item["arquivo"])
            if p.exists():
                files.append(discord.File(str(p), filename=p.name))
        conteudo = texto if inicio == 0 else f"📎 **Continuação dos anexos do relatório** ({inicio+1}–{inicio+len(files)})"
        msg=await canal_destino.send(
            content=conteudo,
            files=files,
            view=view if inicio == 0 else None,
            allowed_mentions=discord.AllowedMentions(users=True, roles=False, everyone=False),
        )
        mensagens.append(msg)
        if not arquivos:
            break
    return mensagens



def _localizar_relatorio_por_mensagem(mensagem_id: int) -> Tuple[Optional[Dict[str, Any]], int]:
    lista = carregar_relatorios_operacionais()
    alvo = str(mensagem_id)
    for indice, registro in enumerate(lista):
        ids = [str(x) for x in (registro.get("mensagens_ids") or [])]
        if str(registro.get("id") or "") == alvo or alvo in ids:
            return registro, indice
    return None, -1


def _atualizar_relatorio_registrado(indice: int, registro: Dict[str, Any]) -> None:
    lista = carregar_relatorios_operacionais()
    if 0 <= indice < len(lista):
        lista[indice] = registro
    else:
        lista.append(registro)
    salvar_relatorios_operacionais(lista)


async def _apagar_mensagens_relatorio(canal, ids: List[int]) -> None:
    for mensagem_id in ids:
        try:
            msg = await canal.fetch_message(int(mensagem_id))
            await msg.delete(reason="Relatório substituído pelo sistema de edição DICOR")
        except Exception:
            pass


class EditarTextoRelatorioModal(Modal):
    def __init__(self, registro: Dict[str, Any]):
        super().__init__(title="Editar relatório DICOR", timeout=600)
        self.registro = registro
        texto_atual = str(registro.get("texto_completo") or "")[:4000]
        self.texto = TextInput(
            label="Texto completo do relatório",
            style=discord.TextStyle.paragraph,
            default=texto_atual,
            max_length=4000,
            required=True,
        )
        self.add_item(self.texto)

    async def on_submit(self, interaction: discord.Interaction):
        await interaction.response.defer(ephemeral=True, thinking=True)
        guild = interaction.guild
        if guild is None:
            return await interaction.followup.send("❌ Servidor não encontrado.", ephemeral=True)

        registro, indice = _localizar_relatorio_por_mensagem(int(self.registro.get("id") or 0))
        if not registro:
            return await interaction.followup.send("❌ O registro desse relatório não foi encontrado.", ephemeral=True)

        tipo = str(registro.get("tipo") or "relatorio")
        numero = str(registro.get("numero") or "000")
        overwrites = {
            guild.default_role: discord.PermissionOverwrite(view_channel=False),
            interaction.user: discord.PermissionOverwrite(view_channel=True, send_messages=True, attach_files=True, embed_links=True, read_message_history=True),
            guild.me: discord.PermissionOverwrite(view_channel=True, send_messages=True, manage_channels=True, manage_messages=True, attach_files=True, read_message_history=True),
        }
        for role in guild.roles:
            if role.id in set(CARGOS_EQUIPE_IDS + CARGOS_ADMIN_IDS):
                overwrites[role] = discord.PermissionOverwrite(view_channel=True, send_messages=True, attach_files=True, read_message_history=True)
        categoria = guild.get_channel(CATEGORIA_RELATORIOS_TEMPORARIOS)
        slug = re.sub(r"[^a-z0-9-]+", "-", normalizar_busca(interaction.user.display_name)).strip("-")[:25]
        canal = await guild.create_text_channel(
            name=f"editar-{tipo}-{numero}-{slug}"[:95],
            category=categoria,
            overwrites=overwrites,
            reason="Edição de relatório operacional DICOR",
        )
        _salvar_draft(canal.id, {
            "modo": "editar",
            "tipo": tipo,
            "numero": numero,
            "texto": str(self.texto.value).strip(),
            "autor_id": registro.get("autor_id"),
            "autor_nome": registro.get("autor_nome"),
            "editor_id": interaction.user.id,
            "editor_nome": str(interaction.user),
            "criado_em": agora_br(),
            "canal_destino_id": registro.get("canal_destino_id"),
            "registro_indice": indice,
            "mensagens_antigas_ids": registro.get("mensagens_ids") or [registro.get("id")],
            "registro_antigo": registro,
        })
        embed = discord.Embed(
            title="✏️ EDITAR FOTOS DO RELATÓRIO",
            description=(
                "O texto editado foi salvo. Agora envie neste canal **somente as fotos e arquivos corretos**.\n\n"
                "Ao finalizar, o bot apagará as mensagens antigas e publicará novamente o relatório com os novos anexos. "
                "Os links antigos não serão mantidos."
            ),
            color=discord.Color.orange(),
        )
        embed.add_field(name="Prévia atualizada", value=cortar_discord(str(self.texto.value).replace("*", ""), 1000), inline=False)
        await canal.send(content=interaction.user.mention, embed=embed, view=FinalizarRelatorioFotosView())
        await interaction.followup.send(f"✅ Edição iniciada. Anexe as fotos corretas em {canal.mention}.", ephemeral=True)


class EditarRelatorioView(View):
    def __init__(self):
        super().__init__(timeout=None)

    @discord.ui.button(label="Editar relatório", emoji="✏️", style=discord.ButtonStyle.primary, custom_id="dicor_relatorio_editar")
    async def editar(self, interaction: discord.Interaction, button: Button):
        if interaction.message is None:
            return await interaction.response.send_message("❌ Mensagem do relatório não encontrada.", ephemeral=True)
        registro, _ = _localizar_relatorio_por_mensagem(interaction.message.id)
        if not registro:
            return await interaction.response.send_message(
                "❌ Este relatório ainda não possui registro editável. Relatórios novos terão o botão funcionando normalmente.",
                ephemeral=True,
            )
        await interaction.response.send_modal(EditarTextoRelatorioModal(registro))


class FinalizarRelatorioFotosView(View):
    def __init__(self):
        super().__init__(timeout=None)

    @discord.ui.button(label="Finalizar relatório", emoji="✅", style=discord.ButtonStyle.success, custom_id="dicor_relatorio_fotos_finalizar")
    async def finalizar(self, interaction: discord.Interaction, button: Button):
        await interaction.response.defer(ephemeral=True, thinking=True)
        canal=interaction.channel
        if not isinstance(canal, discord.TextChannel):
            return await interaction.followup.send("❌ Este botão só funciona no canal provisório.", ephemeral=True)
        draft=_obter_draft(canal.id)
        if not draft:
            return await interaction.followup.send("❌ Rascunho não encontrado. Nada foi apagado.", ephemeral=True)
        if draft.get("modo") != "editar" and interaction.user.id != int(draft.get("autor_id",0)) and not (isinstance(interaction.user,discord.Member) and usuario_tem_admin(interaction.user)):
            return await interaction.followup.send("❌ Apenas o autor ou a administração pode finalizar.", ephemeral=True)
        pasta=RELATORIOS_ARQUIVOS_DIR / str(draft.get("tipo")) / str(draft.get("numero"))
        anexos=await _salvar_anexos_canal(canal,pasta)
        if not anexos:
            return await interaction.followup.send("⚠️ Nenhuma foto foi encontrada. Envie ao menos um anexo antes de finalizar.", ephemeral=True)
        destino_id=int(draft.get("canal_destino_id") or 0)
        destino=interaction.guild.get_channel(destino_id) if interaction.guild else None
        if destino is None:
            try: destino=await bot.fetch_channel(destino_id)
            except Exception: destino=None
        if destino is None:
            return await interaction.followup.send("❌ Canal oficial não encontrado. O canal provisório foi preservado.", ephemeral=True)
        try:
            msgs=await _enviar_relatorio_com_arquivos(destino,str(draft.get("texto","")),anexos,view=EditarRelatorioView())
        except Exception as erro:
            await enviar_log(f"❌ Falha no envio do relatório com fotos: {erro}")
            return await interaction.followup.send("❌ Falha ao enviar. O canal e os arquivos foram preservados para nova tentativa.", ephemeral=True)
        registro={
            "id": str(msgs[0].id), "tipo": draft.get("tipo"), "tipo_nome": nome_tipo_relatorio(draft.get("tipo")),
            "numero": draft.get("numero"), "autor_id": draft.get("autor_id"), "autor_nome": draft.get("autor_nome"),
            "data": agora_br(), "canal_destino_id": destino_id, "mensagem_url": msgs[0].jump_url,
            "mensagens_ids": [m.id for m in msgs], "texto_completo": draft.get("texto"), "provas": anexos,
            "resumo": cortar_discord(str(draft.get("texto","")).replace("*",""),800),
        }
        if draft.get("modo") == "editar":
            antigo = draft.get("registro_antigo") or {}
            registro["criado_em_original"] = antigo.get("criado_em_original") or antigo.get("data")
            registro["editado_em"] = agora_br()
            registro["editado_por_id"] = draft.get("editor_id")
            registro["editado_por_nome"] = draft.get("editor_nome")
            await _apagar_mensagens_relatorio(destino, [int(x) for x in (draft.get("mensagens_antigas_ids") or []) if str(x).isdigit()])
            _atualizar_relatorio_registrado(int(draft.get("registro_indice", -1)), registro)
            await enviar_log(
                f"✏️ Relatório {nome_tipo_relatorio(str(draft.get('tipo')))} Nº {draft.get('numero')} editado por "
                f"<@{draft.get('editor_id')}>. Texto e anexos antigos foram substituídos."
            )
        else:
            registrar_relatorio_operacional(registro)
        _remover_draft(canal.id)
        await interaction.followup.send(
            f"✅ Relatório {'editado e substituído' if draft.get('modo') == 'editar' else 'enviado'} com {len(anexos)} arquivo(s).",
            ephemeral=True,
        )
        await canal.send(
            "✅ Relatório atualizado com sucesso. Este canal será apagado em 8 segundos."
            if draft.get("modo") == "editar"
            else "✅ Formulário e fotos enviados juntos com sucesso. Este canal será apagado em 8 segundos."
        )
        await asyncio.sleep(8)
        try: await canal.delete(reason="Relatório concluído e anexos salvos")
        except Exception: pass

    @discord.ui.button(label="Cancelar", emoji="❌", style=discord.ButtonStyle.danger, custom_id="dicor_relatorio_fotos_cancelar")
    async def cancelar(self, interaction: discord.Interaction, button: Button):
        canal=interaction.channel
        if not isinstance(canal,discord.TextChannel):
            return await interaction.response.send_message("❌ Canal inválido.",ephemeral=True)
        draft=_obter_draft(canal.id) or {}
        permitido = (
            interaction.user.id == int(draft.get("autor_id", 0) or 0)
            or interaction.user.id == int(draft.get("editor_id", 0) or 0)
            or (isinstance(interaction.user, discord.Member) and usuario_tem_admin(interaction.user))
        )
        if not permitido:
            return await interaction.response.send_message("❌ Sem permissão.", ephemeral=True)
        _remover_draft(canal.id)
        await interaction.response.send_message("🗑️ Relatório cancelado. O canal será apagado.",ephemeral=True)
        await asyncio.sleep(3)
        try: await canal.delete(reason="Relatório cancelado")
        except Exception: pass


def _limpar_links_provas_relatorio(texto: str) -> str:
    """Remove URLs antigas de CDN/Discord para que a edição use anexos reais."""
    linhas = []
    ignorar_cabecalho = False
    for linha in str(texto or "").splitlines():
        norm = normalizar_busca(linha) if 'normalizar_busca' in globals() else linha.lower()
        if "registros fotograficos" in norm or "provas em anexo" in norm:
            ignorar_cabecalho = True
            continue
        if re.search(r"https?://(?:cdn|media)\.discordapp\.com/", linha, flags=re.I):
            continue
        if ignorar_cabecalho and (not linha.strip() or linha.lstrip().startswith(("•", "-"))):
            continue
        ignorar_cabecalho = False
        linhas.append(linha)
    return "\n".join(linhas).strip()


async def _localizar_relatorio_antigo(tipo: str, numero: int, guild: Optional[discord.Guild]) -> Tuple[Optional[Dict[str, Any]], int]:
    # Primeiro tenta o banco local dos relatórios já registrados.
    lista = carregar_relatorios_operacionais()
    for indice, registro in enumerate(lista):
        try:
            mesmo_numero = int(str(registro.get("numero") or 0)) == int(numero)
        except Exception:
            mesmo_numero = False
        if str(registro.get("tipo") or "") == tipo and mesmo_numero:
            return registro, indice

    if guild is None:
        return None, -1
    canal_id = CANAIS_RELATORIOS.get(tipo)
    canal = guild.get_channel(canal_id) if canal_id else None
    if canal is None and canal_id:
        try:
            canal = await bot.fetch_channel(canal_id)
        except Exception:
            canal = None
    if canal is None or not hasattr(canal, "history"):
        return None, -1

    # Procura no histórico inteiro para também aceitar relatórios criados antes da atualização.
    async for msg in canal.history(limit=None, oldest_first=False):
        texto = coletar_texto_embed(msg) if 'coletar_texto_embed' in globals() else (msg.content or "")
        if extrair_numero_relatorio_tipo(texto, tipo) != int(numero):
            continue
        texto_limpo = _limpar_links_provas_relatorio(msg.content or texto)
        registro = {
            "id": str(msg.id),
            "tipo": tipo,
            "tipo_nome": nome_tipo_relatorio(tipo),
            "numero": f"{int(numero):03d}",
            "autor_id": getattr(msg.author, "id", 0),
            "autor_nome": str(msg.author),
            "data": agora_br(),
            "canal_destino_id": canal_id,
            "mensagem_url": msg.jump_url,
            "mensagens_ids": [msg.id],
            "texto_completo": texto_limpo,
            "provas": [],
            "resumo": cortar_discord(texto_limpo.replace("*", ""), 800),
            "importado_para_edicao": True,
        }
        lista.append(registro)
        salvar_relatorios_operacionais(lista)
        return registro, len(lista) - 1
    return None, -1


class BuscarRelatorioAntigoModal(Modal, title="Editar relatório antigo"):
    tipo = TextInput(
        label="Tipo do relatório",
        placeholder="tocaia, OLB ou perícia externa",
        max_length=40,
        required=True,
    )
    numero = TextInput(
        label="Número do relatório",
        placeholder="Exemplo: 12",
        max_length=6,
        required=True,
    )

    async def on_submit(self, interaction: discord.Interaction):
        await interaction.response.defer(ephemeral=True, thinking=True)
        tipo_norm = normalizar_busca(self.tipo.value) if 'normalizar_busca' in globals() else self.tipo.value.lower()
        if "tocaia" in tipo_norm:
            tipo = "tocaia"
        elif "olb" in tipo_norm:
            tipo = "olb"
        elif "pericia" in tipo_norm or "externa" in tipo_norm:
            tipo = "pericia_externa"
        else:
            return await interaction.followup.send(
                "❌ Tipo inválido. Use **Tocaia**, **OLB** ou **Perícia Externa**.", ephemeral=True
            )
        numero_txt = re.sub(r"\D+", "", str(self.numero.value))
        if not numero_txt:
            return await interaction.followup.send("❌ Informe um número válido.", ephemeral=True)

        registro, _ = await _localizar_relatorio_antigo(tipo, int(numero_txt), interaction.guild)
        if not registro:
            return await interaction.followup.send(
                f"❌ Não encontrei o relatório **{nome_tipo_relatorio(tipo)} Nº {int(numero_txt):03d}** no canal oficial.",
                ephemeral=True,
            )

        # Como a interação já foi respondida com defer, enviamos um botão temporário para abrir o modal de texto.
        await interaction.followup.send(
            f"✅ Relatório localizado: **{nome_tipo_relatorio(tipo)} Nº {int(numero_txt):03d}**. Clique abaixo para editar.",
            view=AbrirEditorRelatorioEncontradoView(registro),
            ephemeral=True,
        )


