async def finalizar_e_postar_relatorio(interaction: discord.Interaction, tipo: str, texto_conteudo: str):
    # Compatibilidade: agora apenas abre o canal de anexos, sem publicar antes das fotos.
    numero_match=re.search(r"Nº\s+([0-9]+)",texto_conteudo,flags=re.I)
    numero=numero_match.group(1) if numero_match else obter_proximo_numero_relatorio(tipo)
    await _criar_canal_fotos_relatorio(interaction,tipo,texto_conteudo,numero)


# ---------------- HIERARQUIA COM PESSOAS ----------------

def _membros_por_cargo(guild:discord.Guild,termos:List[str])->List[discord.Member]:
    role=_cargo_por_nome(guild,termos)
    if not role:return []
    return sorted([m for m in role.members if not m.bot],key=lambda m:m.display_name.lower())


def _linhas_pessoas(guild:discord.Guild,icone:str,rotulo:str,termos:List[str],fallback_ids:Optional[List[int]]=None)->List[str]:
    membros=_membros_por_cargo(guild,termos)
    if not membros and fallback_ids:
        membros=[m for uid in fallback_ids if (m:=guild.get_member(uid)) is not None]
    return [f"{icone} {rotulo} - {m.mention}" for m in membros] or [f"{icone} {rotulo} - Sem ocupante cadastrado"]


def montar_mensagem_hierarquia_dicor(guild: discord.Guild) -> str:
    linhas=["🏛️ **HIERARQUIA OFICIAL – DICOR** 🏛️","","👑 **ALTO COMANDO**",""]
    linhas += _linhas_pessoas(guild,"🎖️","Delegado Geral",["delegado","geral"],[596518258291507221])
    linhas += _linhas_pessoas(guild,"🎖️","Delegado Adjunto",["delegado","adjunto"],[527894944904511498])
    linhas += ["","🧠 **COMANDO DICOR**",""]
    linhas += _linhas_pessoas(guild,"🎖️","Delegado DICOR",["delegado","dicor"])
    linhas += _linhas_pessoas(guild,"🎖️","Vice-Diretor DICOR",["vice","dicor"])
    linhas += _linhas_pessoas(guild,"🎖️","Inspetor DICOR",["inspetor","dicor"])
    linhas += ["","🔍 **SETOR INVESTIGATIVO**",""]
    linhas += _linhas_pessoas(guild,"🕵️","DICOR – Investigador",["investigador"])
    linhas += ["","📡 **BASE OPERACIONAL**",""]
    est=_membros_por_cargo(guild,["estagiario"]) or _membros_por_cargo(guild,["estagiário"])
    linhas += [f"🧑‍🎓 DICOR – Estagiário - {m.mention}" for m in est] or ["🧑‍🎓 DICOR – Estagiário - Sem ocupante cadastrado"]
    linhas += ["","-----------------------------------------------------","","⚖️ **OBSERVAÇÕES GERAIS**","","• A hierarquia deve ser respeitada em todas as operações","• Ordens superiores devem ser seguidas","• Quebra de hierarquia pode resultar em punição","• Toda ação deve ser reportada conforme o protocolo DICOR","","📍 **DICOR – Capital Morada Valley**"]
    return "\n".join(linhas)


async def enviar_hierarquia_substituindo_anterior() -> None:
    if not HIERARQUIA_CHANNEL_ID:return
    canal=bot.get_channel(HIERARQUIA_CHANNEL_ID)
    if canal is None:
        try:canal=await bot.fetch_channel(HIERARQUIA_CHANNEL_ID)
        except Exception:return
    controle=_json_dict(HIERARQUIA_MENSAGEM_JSON); mid=controle.get("mensagem_id")
    if mid:
        try:
            antiga=await canal.fetch_message(int(mid))
            if antiga.author.id==bot.user.id: await antiga.delete()
        except Exception:pass
    msg=await canal.send(montar_mensagem_hierarquia_dicor(canal.guild),allowed_mentions=discord.AllowedMentions(users=True,roles=False,everyone=False))
    _salvar_dict(HIERARQUIA_MENSAGEM_JSON,{"mensagem_id":msg.id,"data":agora_br()})


