AUTORIZACOES_CHANNEL_ID = env_int("AUTORIZACOES_CHANNEL_ID", LOGS_CHANNEL_ID)
AUTORIZACOES_PENDENTES_JSON = DATA_DIR / "autorizacoes_pendentes.json"
PROCURADOS_RASCUNHOS_JSON = DATA_DIR / "procurados_rascunhos.json"
COMPARECIMENTOS_CONTADOR_JSON = DATA_DIR / "comparecimentos_contador.json"
INSPETOR_PREDADOR_ID = env_int("INSPETOR_PREDADOR_ID", 0)
INSPETOR_BAIANO_ID = env_int("INSPETOR_BAIANO_ID", 0)
NOVO_BRASAO_DICOR_B64 = ""


def caminho_brasao_dicor() -> Optional[Path]:
    """Usa obrigatoriamente o novo brasão DICOR anexado ao projeto."""
    destino = DOSSIE_ASSETS_DIR / "brasao_dicor_novo_oficial.png"
    try:
        bruto = base64.b64decode(NOVO_BRASAO_DICOR_B64)
        if not destino.exists() or destino.stat().st_size != len(bruto):
            destino.parent.mkdir(parents=True, exist_ok=True)
            destino.write_bytes(bruto)
        return destino
    except Exception as erro:
        print(f"Erro ao preparar novo brasão DICOR: {erro}")
        return destino if destino.exists() else None


def mencoes_inspetor_mais(guild: Optional[discord.Guild]) -> str:
    if guild is None:
        return "Diretoria DICOR"
    mencoes = []
    for cargo_id in sorted(CARGOS_AUTORIZADORES):
        cargo = guild.get_role(cargo_id)
        if cargo:
            mencoes.append(cargo.mention)
    return " ".join(mencoes) or "Diretoria DICOR"


def _carregar_autorizacoes() -> Dict[str, Any]:
    dados = carregar_json(AUTORIZACOES_PENDENTES_JSON, {})
    return dados if isinstance(dados, dict) else {}


def _salvar_autorizacoes(dados: Dict[str, Any]) -> None:
    salvar_json(AUTORIZACOES_PENDENTES_JSON, dados)


def _carregar_rascunhos_procurados() -> Dict[str, Any]:
    dados = carregar_json(PROCURADOS_RASCUNHOS_JSON, {})
    return dados if isinstance(dados, dict) else {}


def _salvar_rascunhos_procurados(dados: Dict[str, Any]) -> None:
    salvar_json(PROCURADOS_RASCUNHOS_JSON, dados)


def _registrar_rascunho_procurado(canal_id: int, dados: Dict[str, Any]) -> None:
    todos = _carregar_rascunhos_procurados()
    todos[str(canal_id)] = dados
    _salvar_rascunhos_procurados(todos)
    cadastros_pendentes[int(canal_id)] = dados


def _obter_rascunho_procurado(canal_id: int) -> Optional[Dict[str, Any]]:
    return cadastros_pendentes.get(int(canal_id)) or _carregar_rascunhos_procurados().get(str(canal_id))


def _remover_rascunho_procurado(canal_id: int) -> None:
    cadastros_pendentes.pop(int(canal_id), None)
    todos = _carregar_rascunhos_procurados()
    todos.pop(str(canal_id), None)
    _salvar_rascunhos_procurados(todos)


async def _canal_autorizacoes(guild: Optional[discord.Guild], fallback=None):
    canal = None
    if guild and AUTORIZACOES_CHANNEL_ID:
        canal = guild.get_channel(AUTORIZACOES_CHANNEL_ID)
    if canal is None and AUTORIZACOES_CHANNEL_ID:
        try:
            canal = await bot.fetch_channel(AUTORIZACOES_CHANNEL_ID)
        except Exception:
            canal = None
    return canal if canal is not None and hasattr(canal, "send") else fallback


def _solicitacao_por_mensagem(message_id: int) -> tuple[Optional[str], Optional[Dict[str, Any]]]:
    dados = _carregar_autorizacoes()
    for chave, item in dados.items():
        if int(item.get("mensagem_id") or 0) == int(message_id):
            return chave, item
    return None, None


async def _encerrar_mensagem_autorizacao(interaction: discord.Interaction) -> None:
    try:
        await interaction.message.edit(view=None)
    except Exception:
        pass
    try:
        await interaction.message.delete()
    except Exception:
        pass


class NovoProcuradoModal(Modal, title="Cadastrar Novo Procurado"):
    nome = TextInput(label="Nome", placeholder="Nome do procurado", max_length=100)
    rg = TextInput(label="RG", placeholder="RG do procurado", max_length=50)
    crimes = TextInput(label="Crimes Cometidos", style=discord.TextStyle.paragraph, max_length=1000)
    ultimo = TextInput(label="Último Avistamento", style=discord.TextStyle.paragraph, max_length=600)
    numero_boletim = TextInput(label="Número do boletim", placeholder="Ex: 001", max_length=20, required=True)

    async def on_submit(self, interaction: discord.Interaction):
        guild = interaction.guild
        if guild is None:
            return await interaction.response.send_message("❌ Use dentro de um servidor.", ephemeral=True)
        numero = normalizar_boletim_procurado(str(self.numero_boletim.value))
        if not numero:
            return await interaction.response.send_message("❌ Informe um número de boletim válido.", ephemeral=True)
        await interaction.response.defer(ephemeral=True, thinking=True)
        categoria = guild.get_channel(PROCURADOS_TEMP_CATEGORY_ID) if PROCURADOS_TEMP_CATEGORY_ID else None
        overwrites = {
            guild.default_role: discord.PermissionOverwrite(view_channel=False),
            interaction.user: discord.PermissionOverwrite(view_channel=True, send_messages=True, attach_files=True, read_message_history=True),
        }
        if guild.me:
            overwrites[guild.me] = discord.PermissionOverwrite(view_channel=True, send_messages=True, attach_files=True, read_message_history=True, manage_channels=True)
        for cid in CARGOS_AUTORIZADORES:
            cargo = guild.get_role(cid)
            if cargo:
                overwrites[cargo] = discord.PermissionOverwrite(view_channel=True, send_messages=True, attach_files=True, read_message_history=True)
        canal = await guild.create_text_channel(
            name=f"procurado-{slugify(str(self.nome.value))}"[:100],
            category=categoria,
            overwrites=overwrites,
            reason="Cadastro de procurado aguardando provas",
        )
        dados = {
            "nome": str(self.nome.value), "rg": str(self.rg.value), "crimes": str(self.crimes.value),
            "ultimo_avistamento": str(self.ultimo.value), "numero_boletim": numero,
            "autor_id": interaction.user.id, "autor_nome": str(interaction.user), "criado_em": agora_br(),
        }
        _registrar_rascunho_procurado(canal.id, dados)
        await canal.send(
            "🚨 **Cadastro de Procurado — DICOR**\n\n"
            f"👤 **Nome:** {dados['nome']}\n🪪 **RG:** {dados['rg']}\n📋 **Boletim:** {numero}\n\n"
            "Envie **duas imagens**: foto do indivíduo e foto do RG. Depois clique em **Finalizar Cadastro**.\n"
            "O procurado somente será publicado após autorização da Diretoria DICOR.",
            view=FinalizarProcuradoView(),
        )
        await enviar_log(f"📁 Cadastro provisório criado por {interaction.user} (`{interaction.user.id}`) | RG `{dados['rg']}` | Canal `{canal.id}`")
        await interaction.followup.send(f"✅ Canal criado: {canal.mention}", ephemeral=True)


class FinalizarProcuradoView(View):
    def __init__(self):
        super().__init__(timeout=None)

    @discord.ui.button(label="Finalizar Cadastro", emoji="✅", style=discord.ButtonStyle.green, custom_id="dic_finalizar_procurado")
    async def finalizar(self, interaction: discord.Interaction, button: Button):
        canal = interaction.channel
        if not isinstance(canal, discord.TextChannel):
            return await interaction.response.send_message("❌ Canal inválido.", ephemeral=True)
        dados = _obter_rascunho_procurado(canal.id)
        if not dados:
            return await interaction.response.send_message("❌ Cadastro não encontrado. Abra novamente pelo painel.", ephemeral=True)
        if interaction.user.id != int(dados.get("autor_id") or 0) and not usuario_e_administrador(interaction.user if isinstance(interaction.user, discord.Member) else None):
            return await interaction.response.send_message("❌ Apenas o solicitante ou a Diretoria pode finalizar.", ephemeral=True)
        anexos = []
        async for msg in canal.history(limit=150, oldest_first=True):
            for anexo in msg.attachments:
                if str(anexo.content_type or "").startswith("image/") or Path(anexo.filename).suffix.lower() in {".png", ".jpg", ".jpeg", ".webp"}:
                    anexos.append(anexo)
        if len(anexos) < 2:
            return await interaction.response.send_message("❌ Envie a foto do indivíduo e a foto do RG.", ephemeral=True)
        await interaction.response.defer(ephemeral=True, thinking=True)
        foto_ind = await salvar_anexo_publico(anexos[0], f"individuo-{dados['rg']}")
        foto_rg = await salvar_anexo_publico(anexos[1], f"rg-{dados['rg']}")
        registro = {
            "id": data_caso(), "caso": f"DICOR-{data_caso()}", "data": agora_br(),
            "status": "AGUARDANDO_AUTORIZACAO", "nome": dados["nome"], "rg": dados["rg"],
            "crimes": dados["crimes"], "ultimo_avistamento": dados["ultimo_avistamento"],
            "numero_boletim": dados.get("numero_boletim", ""), "informacoes": dados.get("numero_boletim", ""),
            "foto_individuo": foto_ind, "foto_rg": foto_rg, "autor_id": dados["autor_id"],
            "autor_nome": dados["autor_nome"], "criado_por_id": dados["autor_id"], "criado_por_nome": dados["autor_nome"],
        }
        req_id = f"PROC-CRIAR-{data_caso()}-{canal.id}"
        solicitacao = {
            "id": req_id, "tipo": "criar_procurado", "status": "pendente", "registro": registro,
            "solicitante_id": dados["autor_id"], "solicitante_nome": dados["autor_nome"], "criada_em": agora_br(),
        }
        destino = await _canal_autorizacoes(interaction.guild, canal)
        embed = discord.Embed(title="🚨 Autorização — Criar Procurado", color=discord.Color.orange())
        embed.add_field(name="Nome", value=registro["nome"], inline=True)
        embed.add_field(name="RG", value=f"`{registro['rg']}`", inline=True)
        embed.add_field(name="Boletim", value=registro.get("numero_boletim") or "Não informado", inline=True)
        embed.add_field(name="Crimes", value=cortar_discord(registro.get("crimes", ""), 900), inline=False)
        embed.add_field(name="Solicitado por", value=f"<@{dados['autor_id']}> (`{dados['autor_id']}`)", inline=False)
        msg = await destino.send(
            content=f"{mencoes_inspetor_mais(interaction.guild)}\nSolicitação aguardando autorização da Diretoria DICOR.",
            embed=embed, view=AutorizacaoProcuradoPainelView(),
            allowed_mentions=discord.AllowedMentions(roles=True, users=False, everyone=False),
        )
        solicitacao.update({"mensagem_id": msg.id, "canal_autorizacao_id": msg.channel.id})
        todas = _carregar_autorizacoes(); todas[req_id] = solicitacao; _salvar_autorizacoes(todas)
        _remover_rascunho_procurado(canal.id)
        await enviar_log(f"📩 Solicitação de criação de procurado | Nome `{registro['nome']}` | RG `{registro['rg']}` | Solicitante <@{dados['autor_id']}> | Pedido `{req_id}`")
        await interaction.followup.send("✅ Pedido enviado à Diretoria. O procurado ainda não foi publicado.", ephemeral=True)
        if getattr(destino, "id", None) == canal.id:
            await canal.send("⚠️ O canal de autorizações não foi localizado. Este canal será mantido para que a Diretoria possa decidir aqui.")
        else:
            await canal.send("✅ Provas salvas e autorização solicitada. Este canal será removido.")
            await asyncio.sleep(2)
            try:
                await canal.delete(reason="Cadastro encaminhado para autorização")
            except Exception:
                pass

    @discord.ui.button(label="Cancelar", emoji="❌", style=discord.ButtonStyle.red, custom_id="dic_cancelar_procurado")
    async def cancelar(self, interaction: discord.Interaction, button: Button):
        canal = interaction.channel
        if isinstance(canal, discord.TextChannel):
            _remover_rascunho_procurado(canal.id)
            await interaction.response.send_message("Cadastro cancelado.", ephemeral=True)
            await asyncio.sleep(1)
            try: await canal.delete(reason="Cadastro cancelado")
            except Exception: pass


async def _executar_criacao_procurado(solicitacao: Dict[str, Any], autorizador: discord.Member) -> str:
    registro = dict(solicitacao.get("registro") or {})
    registro.update({
        "status": "A PROCURAR", "autorizado_por_id": autorizador.id,
        "autorizado_por_nome": str(autorizador), "autorizado_por_cargo": autorizador.top_role.name,
        "autorizado_em": agora_br(), "mensagem_id": None, "mensagem_url": None,
    })
    msg = await postar_procurado_oficial(registro)
    if not msg:
        raise RuntimeError("Canal de procurados ativos não encontrado ou sem permissão de envio.")
    registro["mensagem_id"] = msg.id; registro["mensagem_url"] = msg.jump_url; registro["canal_id"] = msg.channel.id
    await salvar_procurado_catalogo(registro)
    return msg.jump_url


async def _executar_retirada_procurado(solicitacao: Dict[str, Any], autorizador: discord.Member) -> str:
    alvo = limpar_rg(solicitacao.get("rg", "")); motivo = str(solicitacao.get("motivo") or "Não informado")
    lista = carregar_procurados(); encontrado = next((r for r in lista if limpar_rg(r.get("rg", "")) == alvo), None)
    if not encontrado:
        raise RuntimeError("Procurado não encontrado.")
    if str(encontrado.get("status", "")).upper() == "RETIRADO":
        raise RuntimeError("Esse procurado já está arquivado.")
    arquivada = await arquivar_procurado_discord(encontrado, motivo, autorizador.mention)
    encontrado.update({
        "status": "RETIRADO", "motivo_retirada": motivo, "data_retirada": agora_br(),
        "retirado_por": str(autorizador), "retirado_por_id": autorizador.id,
        "autorizado_por_id": autorizador.id, "autorizado_por_nome": str(autorizador),
        "autorizado_por_cargo": autorizador.top_role.name, "mensagem_original_id": encontrado.get("mensagem_id"),
        "mensagem_original_url": encontrado.get("mensagem_url"), "mensagem_arquivada_id": arquivada.id,
        "mensagem_arquivada_url": arquivada.jump_url, "mensagem_url": arquivada.jump_url,
    })
    salvar_procurados(lista); gerar_catalogo_html()
    return arquivada.jump_url


class AutorizacaoProcuradoPainelView(View):
    def __init__(self): super().__init__(timeout=None)

    async def _decidir(self, interaction: discord.Interaction, aprovado: bool):
        if not isinstance(interaction.user, discord.Member) or not usuario_e_administrador(interaction.user):
            return await interaction.response.send_message("❌ Apenas Inspetor, Vice-Diretor ou Diretor pode decidir.", ephemeral=True)
        await interaction.response.defer(ephemeral=True, thinking=True)
        chave, sol = _solicitacao_por_mensagem(interaction.message.id)
        if not chave or not sol:
            return await interaction.followup.send("⚠️ Solicitação não encontrada ou já encerrada.", ephemeral=True)
        todas = _carregar_autorizacoes()
        atual = todas.get(chave) or {}
        if atual.get("status") not in {"pendente", "processando"}:
            return await interaction.followup.send("⚠️ Solicitação já decidida.", ephemeral=True)
        atual["status"] = "processando"; todas[chave] = atual; _salvar_autorizacoes(todas)
        try:
            resultado_url = ""
            if aprovado:
                if atual.get("tipo") == "criar_procurado":
                    resultado_url = await _executar_criacao_procurado(atual, interaction.user)
                elif atual.get("tipo") == "retirar_procurado":
                    resultado_url = await _executar_retirada_procurado(atual, interaction.user)
                else:
                    raise RuntimeError("Tipo de autorização desconhecido.")
            atual.update({
                "status": "aprovado" if aprovado else "negado", "decidido_por_id": interaction.user.id,
                "decidido_por_nome": str(interaction.user), "decidido_em": agora_br(), "resultado_url": resultado_url,
            })
            todas[chave] = atual; _salvar_autorizacoes(todas)
            await enviar_log(
                f"{'✅' if aprovado else '❌'} Autorização de procurado | Tipo `{atual.get('tipo')}` | Pedido `{chave}` | "
                f"Solicitante `{atual.get('solicitante_nome')}` (`{atual.get('solicitante_id')}`) | "
                f"Decidido por {interaction.user} (`{interaction.user.id}`) | Resultado: {'APROVADO' if aprovado else 'NEGADO'}"
            )
            await _encerrar_mensagem_autorizacao(interaction)
            await interaction.followup.send(
                ("✅ Ação autorizada e concluída." + (f"\n{resultado_url}" if resultado_url else "")) if aprovado else "❌ Solicitação negada.",
                ephemeral=True,
            )
        except Exception as erro:
            atual["status"] = "falhou"; atual["erro"] = str(erro); todas[chave] = atual; _salvar_autorizacoes(todas)
            await registrar_erro_interacao("AutorizacaoProcuradoPainelView", interaction, erro)

    @discord.ui.button(label="Aprovar", emoji="✅", style=discord.ButtonStyle.green, custom_id="dic_aut_procurado_aprovar")
    async def aprovar(self, interaction: discord.Interaction, button: Button): await self._decidir(interaction, True)

    @discord.ui.button(label="Negar", emoji="❌", style=discord.ButtonStyle.red, custom_id="dic_aut_procurado_negar")
    async def negar(self, interaction: discord.Interaction, button: Button): await self._decidir(interaction, False)


async def retirar_procurado(interaction: discord.Interaction, rg: str, motivo: str):
    if not interaction.response.is_done():
        await interaction.response.defer(ephemeral=True, thinking=True)
    lista = carregar_procurados(); alvo = limpar_rg(rg)
    encontrado = next((r for r in lista if limpar_rg(r.get("rg", "")) == alvo), None)
    if not encontrado:
        return await interaction.followup.send("❌ Procurado não encontrado.", ephemeral=True)
    if str(encontrado.get("status", "")).upper() == "RETIRADO":
        return await interaction.followup.send("⚠️ Esse procurado já está arquivado.", ephemeral=True)
    todas = _carregar_autorizacoes()
    if any(x.get("tipo") == "retirar_procurado" and limpar_rg(x.get("rg", "")) == alvo and x.get("status") in {"pendente", "processando"} for x in todas.values()):
        return await interaction.followup.send("⚠️ Já existe uma retirada aguardando autorização para esse RG.", ephemeral=True)
    req_id = f"PROC-RETIRAR-{data_caso()}-{interaction.user.id}"
    sol = {
        "id": req_id, "tipo": "retirar_procurado", "status": "pendente", "rg": rg, "motivo": motivo,
        "nome": encontrado.get("nome"), "solicitante_id": interaction.user.id,
        "solicitante_nome": str(interaction.user), "criada_em": agora_br(),
    }
    destino = await _canal_autorizacoes(interaction.guild, interaction.channel)
    embed = discord.Embed(title="📁 Autorização — Retirar Procurado", color=discord.Color.orange())
    embed.add_field(name="Nome", value=str(encontrado.get("nome") or "Não informado"), inline=True)
    embed.add_field(name="RG", value=f"`{rg}`", inline=True)
    embed.add_field(name="Motivo", value=cortar_discord(motivo, 900), inline=False)
    embed.add_field(name="Solicitado por", value=interaction.user.mention, inline=False)
    msg = await destino.send(
        content=f"{mencoes_inspetor_mais(interaction.guild)}\nSolicitação aguardando autorização da Diretoria DICOR.",
        embed=embed, view=AutorizacaoProcuradoPainelView(),
        allowed_mentions=discord.AllowedMentions(roles=True, users=False, everyone=False),
    )
    sol.update({"mensagem_id": msg.id, "canal_autorizacao_id": msg.channel.id})
    todas[req_id] = sol; _salvar_autorizacoes(todas)
    await enviar_log(f"📩 Retirada de procurado solicitada | Nome `{sol['nome']}` | RG `{rg}` | Motivo `{motivo}` | Por {interaction.user} (`{interaction.user.id}`)")
    await interaction.followup.send("✅ Solicitação enviada à Diretoria. Nada foi removido ainda.", ephemeral=True)


def proximo_numero_comparecimento() -> str:
    """Reserva imediatamente uma numeração persistente para evitar mandados duplicados."""
    ano = datetime.datetime.now(datetime.timezone(datetime.timedelta(hours=-3))).year
    controle = carregar_json(COMPARECIMENTOS_CONTADOR_JSON, {})
    if not isinstance(controle, dict):
        controle = {}
    maior = int(controle.get(str(ano), 0) or 0)
    for item in carregar_comparecimentos():
        texto = str(item.get("numero") or "")
        m = re.match(r"(\d+)-(\d{4})$", texto)
        if m and int(m.group(2)) == ano:
            maior = max(maior, int(m.group(1)))
    proximo = maior + 1
    controle[str(ano)] = proximo
    salvar_json(COMPARECIMENTOS_CONTADOR_JSON, controle)
    return f"{proximo:05d}-{ano}"


# ---------- ASSINATURAS UNIFICADAS ----------
ASSINATURAS_PERMITIDAS = {
    "diretor_geral": "Diretor Geral",
    "diretor_dicor": "Diretor DICOR",
    "inspetor_predador": "Inspetor Predador",
    "inspetor_baiano": "Inspetor Baiano",
}


def _chave_assinatura_autorizador(usuario_id: Any) -> Optional[str]:
    try: uid = int(usuario_id)
    except Exception: return None
    if INSPETOR_PREDADOR_ID and uid == INSPETOR_PREDADOR_ID: return "inspetor_predador"
    if INSPETOR_BAIANO_ID and uid == INSPETOR_BAIANO_ID: return "inspetor_baiano"
    membro = None
    for guild in bot.guilds:
        membro = guild.get_member(uid)
        if membro:
            break
    nome = normalizar_busca(getattr(membro, "display_name", "")) if membro else ""
    cargos = " ".join(normalizar_busca(getattr(r, "name", "")) for r in getattr(membro, "roles", [])) if membro else ""
    if "predador" in nome:
        return "inspetor_predador"
    if "baiano" in nome:
        return "inspetor_baiano"
    if "diretor geral" in cargos or "delegado geral" in cargos:
        return "diretor_geral"
    if "diretor dicor" in cargos or "delegado dicor" in cargos or any(getattr(r, "id", 0) == 1490200382776021132 for r in getattr(membro, "roles", [])):
        return "diretor_dicor"
    return None


def obter_assinatura_comparecimento(usuario_id: Any) -> Dict[str, Any]:
    uid = str(usuario_id or "").strip()
    # Compatibilidade com assinaturas antigas cadastradas diretamente por ID.
    antigos = _json_dict(ASSINATURAS_COMPARECIMENTO_JSON)
    antigo = dict(antigos.get(uid) or {})
    if antigo.get("arquivo") and Path(str(antigo["arquivo"])).exists():
        return antigo
    chave = _chave_assinatura_autorizador(usuario_id)
    registros = carregar_assinaturas_dossie()
    reg = dict(registros.get(chave) or {}) if chave else {}
    caminho = caminho_assinatura_registrada(reg)
    if caminho:
        reg["arquivo"] = str(caminho)
    if chave:
        reg.setdefault("nome", ASSINATURAS_PERMITIDAS[chave])
        reg.setdefault("cargo", ASSINATURAS_PERMITIDAS[chave])
    try:
        uid_int = int(uid)
        membro = next((g.get_member(uid_int) for g in bot.guilds if g.get_member(uid_int)), None)
        if membro:
            reg.setdefault("nome", membro.display_name)
            reg.setdefault("cargo", membro.top_role.name)
    except Exception:
        pass
    return reg


