@bot.tree.command(name="assinaturas", description="Cadastra, visualiza ou remove uma assinatura institucional DICOR.")
@app_commands.describe(tipo="Assinatura", acao="Ação", arquivo="Imagem PNG/JPG/WEBP para cadastro")
@app_commands.choices(
    tipo=[app_commands.Choice(name=v, value=k) for k, v in ASSINATURAS_PERMITIDAS.items()],
    acao=[
        app_commands.Choice(name="Cadastrar/Substituir", value="cadastrar"),
        app_commands.Choice(name="Visualizar", value="visualizar"),
        app_commands.Choice(name="Remover", value="remover"),
    ],
)
async def assinaturas(interaction: discord.Interaction, tipo: app_commands.Choice[str], acao: app_commands.Choice[str], arquivo: Optional[discord.Attachment] = None):
    if not isinstance(interaction.user, discord.Member) or not usuario_e_administrador(interaction.user):
        return await interaction.response.send_message("❌ Apenas a Diretoria DICOR pode editar assinaturas.", ephemeral=True)
    chave = tipo.value; dados = carregar_assinaturas_dossie(); registro = dict(dados.get(chave) or {})
    if acao.value == "visualizar":
        caminho = caminho_assinatura_registrada(registro)
        if not caminho:
            return await interaction.response.send_message(f"⚠️ Não há imagem cadastrada para **{tipo.name}**.", ephemeral=True)
        return await interaction.response.send_message(
            f"✍️ **Assinatura cadastrada: {tipo.name}**\nAtualizada em: {registro.get('atualizado_em', 'Não informado')}",
            file=discord.File(str(caminho), filename=caminho.name), ephemeral=True,
        )
    if acao.value == "remover":
        caminho = caminho_assinatura_registrada(registro)
        if caminho:
            try: caminho.unlink()
            except Exception: pass
        dados.pop(chave, None); salvar_assinaturas_dossie(dados)
        await enviar_log(f"🗑️ Assinatura `{tipo.name}` removida por {interaction.user} (`{interaction.user.id}`)")
        return await interaction.response.send_message(f"✅ Assinatura de **{tipo.name}** removida.", ephemeral=True)
    if arquivo is None or not str(arquivo.content_type or "").startswith("image/"):
        return await interaction.response.send_message("❌ Para cadastrar, envie uma imagem PNG, JPG ou WEBP.", ephemeral=True)
    await interaction.response.defer(ephemeral=True, thinking=True)
    destino = ASSINATURAS_DOSSIE_DIR / chave
    caminho = await salvar_imagem_assinatura(arquivo, destino)
    dados[chave] = {
        "nome": tipo.name, "cargo": tipo.name, "arquivo": caminho_relativo_base(caminho),
        "atualizado_por": str(interaction.user), "atualizado_por_id": interaction.user.id, "atualizado_em": agora_br(),
    }
    salvar_assinaturas_dossie(dados)
    await enviar_log(f"✍️ Assinatura `{tipo.name}` cadastrada/substituída por {interaction.user} (`{interaction.user.id}`)")
    await interaction.followup.send(f"✅ Assinatura de **{tipo.name}** salva.", ephemeral=True)


# ---------- ENVIO DIRETO DOS PDFs ----------
async def enviar_arquivos_dossie_destino(
    destino, dados_dossie: Dict[str, Any], arquivos: Dict[str, str], nome_pdf: str,
    nome_docx: str, canal_mesa: discord.TextChannel, usuario: discord.abc.User,
    titulo: str = "🏛️ DOSSIÊ OPERACIONAL AUTOMÁTICO DICOR",
) -> Optional[discord.Message]:
    if not destino or not hasattr(destino, "send"):
        return None
    caminho = Path(str(arquivos.get("pdf") or ""))
    if not caminho.exists() or caminho.stat().st_size <= 4:
        raise RuntimeError("O PDF do dossiê não foi gerado ou está vazio.")
    with caminho.open("rb") as f:
        if f.read(4) != b"%PDF":
            raise RuntimeError("O arquivo gerado não é um PDF válido.")
    limite = getattr(getattr(destino, "guild", None), "filesize_limit", 25 * 1024 * 1024)
    if caminho.stat().st_size > limite:
        await enviar_log(f"❌ Dossiê `{caminho.name}` ultrapassou o limite do Discord: {caminho.stat().st_size} bytes")
        return await destino.send("❌ O PDF do dossiê ultrapassa o limite de arquivo deste servidor. Reduza o tamanho das imagens da mesa.")
    embed = discord.Embed(title=titulo, description="PDF oficial anexado diretamente para download.", color=discord.Color.from_rgb(0, 43, 91))
    embed.add_field(name="Processo", value=f"`{dados_dossie.get('processo', 'Não informado')}`", inline=True)
    embed.add_field(name="Investigação", value=f"`{dados_dossie.get('numero_investigacao', 'Não informado')}`", inline=True)
    embed.add_field(name="Mesa", value=getattr(canal_mesa, "mention", str(canal_mesa)), inline=False)
    msg = await destino.send(
        content="📄 **Dossiê Operacional DICOR — PDF para download**",
        embed=embed, file=discord.File(str(caminho), filename=_safe_filename(nome_pdf)),
        allowed_mentions=discord.AllowedMentions.none(),
    )
    await enviar_log(f"📄 Dossiê enviado como anexo | Arquivo `{nome_pdf}` | Canal `{getattr(destino, 'id', 0)}` | Por `{getattr(usuario, 'id', 0)}`")
    return msg


async def gerar_e_enviar_comparecimento(interaction: discord.Interaction, atendimento: Dict[str, Any], registro: Dict[str, Any]) -> Dict[str, Any]:
    pasta = COMPARECIMENTOS_DIR / slugify(str(registro.get("numero") or registro.get("id") or data_caso()))
    pasta.mkdir(parents=True, exist_ok=True)
    numero_limpo = re.sub(r"[^0-9A-Za-z_-]+", "_", str(registro.get("numero", "comparecimento")))
    nome_pdf = f"SOLICITACAO_COMPARECIMENTO_{numero_limpo}.pdf"
    caminho_pdf = pasta / nome_pdf
    await asyncio.to_thread(gerar_pdf_comparecimento, registro, caminho_pdf)
    if not caminho_pdf.exists() or caminho_pdf.stat().st_size <= 4:
        raise RuntimeError("O PDF do comparecimento foi gerado vazio.")
    with caminho_pdf.open("rb") as f:
        if f.read(4) != b"%PDF":
            raise RuntimeError("O documento gerado não é um PDF válido.")
    registro["arquivo_pdf"] = str(caminho_pdf); registro["arquivo_docx"] = ""; registro["falhas"] = []
    destino = interaction.guild.get_channel(MANDADOS_CHANNEL_ID) if interaction.guild else None
    if destino is None:
        try: destino = await bot.fetch_channel(MANDADOS_CHANNEL_ID)
        except Exception: destino = interaction.channel
    if destino is None or not hasattr(destino, "send"):
        raise RuntimeError("Canal de mandados não encontrado.")
    limite = getattr(getattr(destino, "guild", None), "filesize_limit", 25 * 1024 * 1024)
    if caminho_pdf.stat().st_size > limite:
        raise RuntimeError("O PDF ultrapassa o limite de envio do Discord.")
    embed = discord.Embed(title="📩 Solicitação de Comparecimento", description="PDF oficial anexado diretamente para download.", color=discord.Color.from_rgb(0, 43, 91))
    embed.add_field(name="Solicitação", value=f"`{registro.get('numero')}`", inline=True)
    embed.add_field(name="Convocado", value=f"{registro.get('nome')} — RG `{registro.get('rg')}`", inline=False)
    embed.add_field(name="Autoridade responsável", value=f"{registro.get('autorizado_por_nome')}\n{registro.get('autorizado_por_cargo')}", inline=False)
    mensagem = await destino.send(
        content="📄 **Solicitação de Comparecimento DICOR — PDF para download**",
        embed=embed, file=discord.File(str(caminho_pdf), filename=_safe_filename(nome_pdf)),
        allowed_mentions=discord.AllowedMentions.none(),
    )
    registro.update({"publicacao_id": mensagem.id, "publicacao_url": mensagem.jump_url, "publicacao_canal_id": destino.id})
    lista = carregar_comparecimentos(); lista.append(registro); salvar_comparecimentos(lista)
    await enviar_log(f"📄 Mandado enviado como PDF | Nº `{registro.get('numero')}` | Autorizado por `{registro.get('autorizado_por_id')}` | Canal `{destino.id}`")
    if interaction.channel and getattr(interaction.channel, "id", None) != destino.id:
        await interaction.channel.send(f"✅ Mandado `{registro.get('numero')}` publicado em {destino.mention}.")
    return registro


# ---------- PAINEL NORMAL DE MANDADOS ----------
class MandadoNormalModal(Modal, title="Solicitação de Comparecimento"):
    nome = TextInput(label="Nome do convocado", max_length=120)
    rg = TextInput(label="RG", max_length=50)
    motivo = TextInput(label="Motivo", style=discord.TextStyle.paragraph, max_length=900)
    data_hora = TextInput(label="Data e horário", placeholder="Ex: 20/07 às 20h", max_length=120)
    local = TextInput(label="Local", max_length=160)

    async def on_submit(self, interaction: discord.Interaction):
        await interaction.response.defer(ephemeral=True, thinking=True)
        registro = preparar_registro_comparecimento(
            {"numero": "PAINEL-DICOR"},
            {"nome": str(self.nome.value), "rg": str(self.rg.value), "motivo": str(self.motivo.value), "data_hora": str(self.data_hora.value), "local": str(self.local.value)},
            interaction.user,
        )
        req_id = f"MANDADO-{data_caso()}-{interaction.user.id}"
        sol = {"id": req_id, "tipo": "mandado_normal", "status": "pendente", "registro": registro, "solicitante_id": interaction.user.id, "solicitante_nome": str(interaction.user), "criada_em": agora_br()}
        destino = await _canal_autorizacoes(interaction.guild, interaction.channel)
        embed = discord.Embed(title="📩 Autorização — Solicitação de Comparecimento", color=discord.Color.orange())
        embed.add_field(name="Convocado", value=f"{registro['nome']} — RG `{registro['rg']}`", inline=False)
        embed.add_field(name="Data/Horário", value=registro["data_hora"], inline=True)
        embed.add_field(name="Local", value=registro["local"], inline=True)
        embed.add_field(name="Motivo", value=cortar_discord(registro["motivo"], 900), inline=False)
        msg = await destino.send(content=f"{mencoes_inspetor_mais(interaction.guild)}\nSolicitação aguardando autorização da Diretoria DICOR.", embed=embed, view=AutorizacaoMandadoNormalView(), allowed_mentions=discord.AllowedMentions(roles=True, users=False, everyone=False))
        sol.update({"mensagem_id": msg.id, "canal_autorizacao_id": msg.channel.id}); todas = _carregar_autorizacoes(); todas[req_id] = sol; _salvar_autorizacoes(todas)
        await enviar_log(f"📩 Mandado solicitado pelo painel | Convocado `{registro['nome']}` | RG `{registro['rg']}` | Por {interaction.user} (`{interaction.user.id}`)")
        await interaction.followup.send("✅ Mandado enviado para autorização.", ephemeral=True)


class AutorizacaoMandadoNormalView(View):
    def __init__(self): super().__init__(timeout=None)

    async def _decidir(self, interaction: discord.Interaction, aprovado: bool):
        if not isinstance(interaction.user, discord.Member) or not usuario_e_administrador(interaction.user):
            return await interaction.response.send_message("❌ Apenas Inspetor, Vice-Diretor ou Diretor pode decidir.", ephemeral=True)
        await interaction.response.defer(ephemeral=True, thinking=True)
        chave, sol = _solicitacao_por_mensagem(interaction.message.id)
        if not chave or not sol or sol.get("tipo") != "mandado_normal":
            return await interaction.followup.send("⚠️ Solicitação não encontrada.", ephemeral=True)
        todas = _carregar_autorizacoes(); atual = todas.get(chave) or {}
        if atual.get("status") != "pendente": return await interaction.followup.send("⚠️ Solicitação já decidida.", ephemeral=True)
        atual["status"] = "processando"; todas[chave] = atual; _salvar_autorizacoes(todas)
        try:
            if aprovado:
                registro = dict(atual.get("registro") or {})
                registro.update({"autorizado_por_id": interaction.user.id, "autorizado_por_nome": str(interaction.user), "autorizado_por_cargo": interaction.user.top_role.name, "autorizado_em": agora_br()})
                await gerar_e_enviar_comparecimento(interaction, {"numero": "PAINEL-DICOR"}, registro)
            atual.update({"status": "aprovado" if aprovado else "negado", "decidido_por_id": interaction.user.id, "decidido_por_nome": str(interaction.user), "decidido_em": agora_br()})
            todas[chave] = atual; _salvar_autorizacoes(todas)
            await enviar_log(f"{'✅' if aprovado else '❌'} Mandado do painel {'autorizado' if aprovado else 'negado'} por {interaction.user} (`{interaction.user.id}`) | Pedido `{chave}`")
            await _encerrar_mensagem_autorizacao(interaction)
            await interaction.followup.send("✅ Mandado autorizado e PDF publicado." if aprovado else "❌ Mandado negado.", ephemeral=True)
        except Exception as erro:
            atual["status"] = "falhou"; atual["erro"] = str(erro); todas[chave] = atual; _salvar_autorizacoes(todas)
            await registrar_erro_interacao("AutorizacaoMandadoNormalView", interaction, erro)

    @discord.ui.button(label="Aprovar", emoji="✅", style=discord.ButtonStyle.green, custom_id="dic_aut_mandado_normal_aprovar")
    async def aprovar(self, interaction: discord.Interaction, button: Button): await self._decidir(interaction, True)
    @discord.ui.button(label="Negar", emoji="❌", style=discord.ButtonStyle.red, custom_id="dic_aut_mandado_normal_negar")
    async def negar(self, interaction: discord.Interaction, button: Button): await self._decidir(interaction, False)


