# ---------- BOLETINS PRIVADOS E ESCOLHA MANUAL DE AGENTE ----------
def buscar_atendimento_por_chave(chave: str, valor: Any) -> Optional[Dict[str, Any]]:
    alvo = str(valor or "")
    for item in carregar_atendimentos_boletins():
        if str(item.get(chave) or "") == alvo:
            return item
    return None


class EscolherAgenteSelect(discord.ui.Select):
    def __init__(self, atendimento_id: str, guild: discord.Guild):
        elegiveis = membros_elegiveis_rodizio(guild)
        options = [
            discord.SelectOption(
                label=m.display_name[:100],
                value=str(m.id),
                description=(m.top_role.name or "Agente DICOR")[:100],
            )
            for m in elegiveis[:25]
        ]
        if not options:
            options = [discord.SelectOption(label="Nenhum agente elegível", value="0", description="Verifique os cargos de Estagiário/Investigador")]
        super().__init__(placeholder="Selecione o agente responsável", min_values=1, max_values=1, options=options)
        self.atendimento_id = atendimento_id

    async def callback(self, interaction: discord.Interaction):
        if not isinstance(interaction.user, discord.Member) or not usuario_e_administrador(interaction.user):
            return await interaction.response.send_message("❌ Apenas a Diretoria pode escolher o agente.", ephemeral=True)
        try:
            agente_id = int(self.values[0])
        except Exception:
            agente_id = 0
        agente = interaction.guild.get_member(agente_id) if interaction.guild and agente_id else None
        if agente is None or agente.bot or agente not in membros_elegiveis_rodizio(interaction.guild):
            return await interaction.response.send_message("❌ Selecione um Estagiário ou Investigador válido.", ephemeral=True)
        atendimento = buscar_atendimento_por_chave("id", self.atendimento_id)
        if not atendimento:
            return await interaction.response.send_message("❌ Atendimento não encontrado.", ephemeral=True)
        canal = interaction.guild.get_channel(int(atendimento.get("area_id") or 0)) if interaction.guild else None
        if not isinstance(canal, discord.TextChannel):
            return await interaction.response.send_message("❌ Canal privado do boletim não encontrado.", ephemeral=True)
        await interaction.response.defer(ephemeral=True, thinking=True)
        antigo_id = int(atendimento.get("agente_id") or 0)
        if antigo_id and antigo_id != agente.id:
            antigo = interaction.guild.get_member(antigo_id)
            if antigo:
                try:
                    await canal.set_permissions(antigo, overwrite=None, reason="Troca de responsável do boletim")
                except Exception:
                    pass
        await canal.set_permissions(
            agente,
            view_channel=True,
            send_messages=True,
            attach_files=True,
            read_message_history=True,
            reason="Agente escolhido pela Diretoria",
        )
        atendimento.update({
            "agente_id": agente.id,
            "agente_nome": str(agente),
            "status": "EM ATENDIMENTO",
            "agente_escolhido_por_id": interaction.user.id,
            "agente_escolhido_por_nome": str(interaction.user),
            "agente_escolhido_em": agora_br(),
        })
        hist = atendimento.get("historico", []) if isinstance(atendimento.get("historico"), list) else []
        hist.append({
            "acao": "Agente escolhido" if not antigo_id else "Agente alterado",
            "usuario": str(interaction.user),
            "usuario_id": interaction.user.id,
            "agente_id": agente.id,
            "agente_nome": str(agente),
            "data": agora_br(),
        })
        atendimento["historico"] = hist[-500:]
        atualizar_atendimento_boletim("id", atendimento.get("id"), atendimento)
        try:
            painel = await canal.fetch_message(int(atendimento.get("painel_msg_id") or 0))
            await painel.edit(
                content=f"🛠️ **Painel do boletim**\n**Agente responsável:** {agente.mention}\nEscolhido por: {interaction.user.mention}",
                view=BoletimAtendimentoView(),
            )
        except Exception:
            pass
        await canal.send(
            f"👮 {agente.mention} foi escolhido como responsável por {interaction.user.mention} em **{agora_br()}**.",
            allowed_mentions=discord.AllowedMentions(users=True, roles=False, everyone=False),
        )
        await enviar_log(
            f"👮 Agente escolhido/trocado | Boletim `{atendimento.get('numero')}` | "
            f"Agente {agente} (`{agente.id}`) | Por {interaction.user} (`{interaction.user.id}`) | "
            f"Anterior `{antigo_id or 'nenhum'}`"
        )
        await interaction.followup.send(f"✅ {agente.mention} agora possui acesso ao boletim.", ephemeral=True)


class EscolherAgenteView(View):
    def __init__(self, atendimento_id: str, guild: discord.Guild):
        super().__init__(timeout=180)
        self.add_item(EscolherAgenteSelect(atendimento_id, guild))


class BoletimAtendimentoView(View):
    def __init__(self): super().__init__(timeout=None)

    @discord.ui.button(label="Escolher Agente", emoji="👮", style=discord.ButtonStyle.blurple, custom_id="dic_bo_escolher_agente")
    async def escolher(self, interaction: discord.Interaction, button: Button):
        if not isinstance(interaction.user, discord.Member) or not usuario_e_administrador(interaction.user):
            return await interaction.response.send_message("❌ Apenas Inspetor, Vice-Diretor ou Diretor pode escolher o agente.", ephemeral=True)
        atendimento = await garantir_atendimento_interaction(interaction)
        if not atendimento:
            return await interaction.response.send_message("❌ Atendimento não encontrado.", ephemeral=True)
        await interaction.response.send_message("Selecione o agente responsável:", view=EscolherAgenteView(str(atendimento.get("id")), interaction.guild), ephemeral=True)

    @discord.ui.button(label="Finalizar Boletim", emoji="✅", style=discord.ButtonStyle.green, custom_id="dic_bo_finalizar")
    async def finalizar(self, interaction: discord.Interaction, button: Button):
        atendimento = await garantir_atendimento_interaction(interaction)
        if not atendimento: return await interaction.response.send_message("❌ Atendimento não encontrado.", ephemeral=True)
        if atendimento.get("status") == "FINALIZADO": return await interaction.response.send_message("⚠️ Este boletim já foi finalizado.", ephemeral=True)
        await interaction.response.send_modal(FinalizarBoletimAtendimentoModal())

    @discord.ui.button(label="Solicitar Comparecimento", emoji="📩", style=discord.ButtonStyle.secondary, custom_id="dic_bo_comparecimento")
    async def comparecimento(self, interaction: discord.Interaction, button: Button): await interaction.response.send_modal(ComparecimentoBoletimModal())

    @discord.ui.button(label="Cadastrar como Procurado", emoji="🚨", style=discord.ButtonStyle.danger, custom_id="dic_bo_cadastrar_procurado")
    async def cadastrar_procurado(self, interaction: discord.Interaction, button: Button):
        atendimento = await garantir_atendimento_interaction(interaction); texto = ""
        if atendimento:
            try:
                canal_origem = interaction.guild.get_channel(int(atendimento.get("canal_origem_id") or 0))
                if canal_origem:
                    msg = await canal_origem.fetch_message(int(atendimento.get("mensagem_original_id")))
                    texto = coletar_texto_embed(msg)
            except Exception: pass
        await interaction.response.send_modal(ProcuradoBoletimModal(extrair_dados_procurado_de_texto(texto)))


async def criar_area_atendimento_boletim(message: discord.Message) -> Optional[Dict[str, Any]]:
    if buscar_atendimento_por_mensagem(message.id): return None
    numero = numero_boletim_de_texto(coletar_texto_embed(message) or message.content or "")
    if buscar_atendimento_por_numero(numero): return None
    base = message.guild.get_channel(BOLETIM_ATENDIMENTO_CHANNEL_ID) if message.guild else None
    if base is None:
        await enviar_log(f"❌ Canal base de boletins `{BOLETIM_ATENDIMENTO_CHANNEL_ID}` não encontrado.")
        return None
    categoria = getattr(base, "category", None)
    overwrites = {message.guild.default_role: discord.PermissionOverwrite(view_channel=False)}
    if message.guild.me:
        overwrites[message.guild.me] = discord.PermissionOverwrite(view_channel=True, send_messages=True, attach_files=True, read_message_history=True, manage_channels=True)
    for cid in CARGOS_AUTORIZADORES:
        cargo = message.guild.get_role(cid)
        if cargo:
            overwrites[cargo] = discord.PermissionOverwrite(view_channel=True, send_messages=True, attach_files=True, read_message_history=True, manage_messages=True)
    nome_canal = f"boletim-{numero_curto_boletim(numero)}-{str(message.id)[-4:]}".lower().replace("/", "-")[:100]
    try:
        area = await message.guild.create_text_channel(name=nome_canal, category=categoria, overwrites=overwrites, reason="Boletim privado para análise da Diretoria")
        texto_original = coletar_texto_embed(message) or message.content or "Sem texto."
        pasta = BOLETIM_ARQUIVOS_DIR / numero.replace("/", "-")
        anexos = await arquivos_para_reenvio_de_mensagens([message], pasta, numero)
        await area.send(
            "📋 **NOVO BOLETIM RECEBIDO**\n━━━━━━━━━━━━━━━━━━━━━━━\n"
            f"**Boletim:** Nº `{numero_curto_boletim(numero)}`\n**Status:** aguardando escolha de agente\n"
            f"**Autor:** {message.author.mention}\n**Recebido em:** {agora_br()}\n**Original:** {message.jump_url}\n\n"
            "Inicialmente, somente a Diretoria DICOR possui acesso a este canal.",
            allowed_mentions=discord.AllowedMentions(users=False, roles=False, everyone=False),
        )
        texto = f"📄 **BOLETIM ORIGINAL COMPLETO**\n━━━━━━━━━━━━━━━━━━━━━━━\n{cortar_discord(texto_original, 1650)}"
        if anexos: await enviar_texto_com_anexos_path(area, texto, anexos, f"Anexos restantes do boletim {numero}")
        else: await area.send(texto)
        painel = await area.send(
            f"{mencoes_inspetor_mais(message.guild)}\n🛠️ **Painel do boletim**\nEscolha um agente responsável antes de encaminhar a análise.",
            view=BoletimAtendimentoView(),
            allowed_mentions=discord.AllowedMentions(roles=True, users=False, everyone=False),
        )
        atendimento = {
            "id": f"ATD-{message.id}", "numero": numero, "mensagem_original_id": message.id,
            "mensagem_original_url": message.jump_url, "canal_origem_id": message.channel.id,
            "area_id": area.id, "thread_id": None, "painel_msg_id": painel.id,
            "agente_id": None, "agente_nome": "Não definido", "autor_id": message.author.id,
            "autor_nome": str(message.author), "status": "AGUARDANDO AGENTE", "data_criacao": agora_br(),
            "anexos_salvos": [str(p) for p in anexos],
            "historico": [{"acao": "Boletim privado criado", "usuario": "Sistema", "data": agora_br()}],
            "comparecimento_status": "não solicitado", "procurado_status": "não solicitado",
        }
        lista = carregar_atendimentos_boletins(); lista.append(atendimento); salvar_atendimentos_boletins(lista)
        await enviar_log(f"📋 Boletim privado criado | Nº `{numero}` | Canal `{area.id}` | Autor `{message.author.id}` | Aguardando escolha de agente")
        return atendimento
    except Exception as erro:
        await enviar_log(f"❌ Erro ao criar boletim privado `{numero}`: {erro}\n```{traceback.format_exc()[-1500:]}```")
        return None


views_correcao_final_registradas = False


@bot.listen("on_ready")
async def carregar_views_correcao_final_dicor():
    """Restaura somente as Views novas; nunca publica relatórios ou hierarquia no início."""
    global views_correcao_final_registradas
    try:
        if not views_correcao_final_registradas:
            for view in (
                AutorizacaoProcuradoPainelView(),
                AutorizacaoMandadoNormalView(),
                PainelMandadosView(),
            ):
                bot.add_view(view)
            views_correcao_final_registradas = True
        try:
            if hierarquia_dicor_automatica.is_running():
                hierarquia_dicor_automatica.cancel()
        except Exception:
            pass
        try:
            if hierarquia_dicor_pessoas_automatica.is_running():
                hierarquia_dicor_pessoas_automatica.cancel()
        except Exception:
            pass
        print("✅ Inicialização segura: nenhuma hierarquia ou relatório foi republicado.")
    except Exception as erro:
        await enviar_log(f"⚠️ Falha ao restaurar Views finais: {erro}")


async def main():
    carregar_boletins_pendentes_memoria()
    garantir_56_organizacoes()
    garantir_senha_catalogo()
    if not DISCORD_TOKEN or DISCORD_TOKEN == "COLE_O_TOKEN_DO_BOT_AQUI":
        print("ERRO: Coloque o token correto nas variáveis do Railway ou no arquivo .env.")
        return
    await start_web_server()
    await bot.start(DISCORD_TOKEN)

if __name__ == "__main__":
    asyncio.run(main())
